INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (428, 2, 'https://cafef.vn/hoa-toc-cuc-thue-de-nghi-kiem-tra-doanh-nghiep-xang-dau-co-giao-dich-bat-thuong-truoc-ngay-dieu-chinh-gia-188260406150557846.chn', 'https://cafef.vn/hoa-toc-cuc-thue-de-nghi-kiem-tra-doanh-nghiep-xang-dau-co-giao-dich-bat-thuong-truoc-ngay-dieu-chinh-gia-188260406150557846.chn', 'Hỏa tốc: Cục thuế đề nghị kiểm tra doanh nghiệp xăng dầu có giao dịch bất thường trước ngày điều chỉnh giá', '<a href="https://cafef.vn/hoa-toc-cuc-thue-de-nghi-kiem-tra-doanh-nghiep-xang-dau-co-giao-dich-bat-thuong-truoc-ngay-dieu-chinh-gia-188260406150557846.chn"><img src="https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/6/avatar1775462712738-17754627141101873514063.jpg"></a> Cục Thuế vừa ban hành công văn hỏa tốc yêu cầu toàn ngành tăng cường kiểm tra, xử lý vi phạm về thuế trong kinh doanh xăng dầu. Trọng tâm là rà soát dữ liệu hóa đơn điện tử, doanh thu, tồn kho trước và sau các đợt điều chỉnh giá, qua đó phát hiện dấu hiệu bất thường, gian lận hoặc trục lợi.', 'Cục Thuế vừa ban hành công văn hỏa tốc yêu cầu toàn ngành tăng cường kiểm tra, xử lý vi phạm về thuế trong kinh doanh xăng dầu. Trọng tâm là rà soát dữ liệu hóa đơn điện tử, doanh thu, tồn kho trước và sau các đợt điều chỉnh giá, qua đó phát hiện dấu hiệu bất thường, gian lận hoặc trục lợi.', 'https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/6/avatar1775462712738-17754627141101873514063.jpg', NULL, '2026-04-06 08:05:00+00', 'Doanh nghiệp | cafef', 'https://cafef.vn/doanh-nghiep.chn', '{"guid": "https://cafef.vn/hoa-toc-cuc-thue-de-nghi-kiem-tra-doanh-nghiep-xang-dau-co-giao-dich-bat-thuong-truoc-ngay-dieu-chinh-gia-188260406150557846.chn", "link": "https://cafef.