INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1905, 61, 'https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-tin-nong-176260401153811523.chn', 'https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-tin-nong-176260401153811523.chn', 'Diễn biến chứng khoán toàn cầu trước tin nóng', '<a href="https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-tin-nong-176260401153811523.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/1/avatar1775032591904-17750325921991121832510.webp"></a> Ngày 1/4, chỉ số MSCI khu vực châu Á - Thái Bình Dương bên ngoài Nhật Bản tăng 2,7%, chấm dứt chuỗi bốn phiên giảm. Tại Hàn Quốc, chỉ số Kospi tăng tới 5,5%, Nikkei 225 của Nhật Bản có lúc tăng 3,9%. Đà tăng được thúc đẩy bởi phát biểu của ông Donald Trump về khả năng kết thúc chiến sự trong vài tuần tới.', 'Ngày 1/4, chỉ số MSCI khu vực châu Á - Thái Bình Dương bên ngoài Nhật Bản tăng 2,7%, chấm dứt chuỗi bốn phiên giảm. Tại Hàn Quốc, chỉ số Kospi tăng tới 5,5%, Nikkei 225 của Nhật Bản có lúc tăng 3,9%. Đà tăng được thúc đẩy bởi phát biểu của ông Donald Trump về khả năng kết thúc chiến sự trong vài tuần tới.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/1/avatar1775032591904-17750325921991121832510.webp', NULL, '2026-04-01 09:52:00+00', 'Chứng khoán | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/chung-khoan.chn', '{"guid": "https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-tin-nong-176260401153811523.chn", "link": "https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-tin-nong-176260401153811523.chn", "title": "Diễn biến chứng khoán toàn cầu trước tin nóng", "content": "<a href=\"https://cafebiz.vn/dien-bien-chung-khoan-toan-cau-truoc-ti