INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (180, 4, 'https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm', 'https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm', 'Khu tây TP.HCM: Dòng tiền đổ về mạnh, nhưng sức mua vẫn dồn vào trung tâm', '<a href="https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/20/1-1773987897007418167184-0-30-688-1131-crop-17739881523641217274825.jpg"></a> Bến Lức đang tăng trưởng nhanh nhờ hạ tầng, c&ocirc;ng nghiệp v&agrave; d&acirc;n cư dịch chuyển. Nhưng khi cần mua sắm, giải tr&iacute; hay tận hưởng cuối tuần, nhiều người vẫn t&igrave;m về TP.HCM. Điều khu t&acirc;y c&ograve;n thiếu l&uacute;c n&agrave;y kh&ocirc;ng chỉ l&agrave; nh&agrave; ở, m&agrave; l&agrave; một &quot;l&otilde;i sống&quot; đủ mạnh để giữ sức mua ở lại.', 'Bến Lức đang tăng trưởng nhanh nhờ hạ tầng, công nghiệp và dân cư dịch chuyển. Nhưng khi cần mua sắm, giải trí hay tận hưởng cuối tuần, nhiều người vẫn tìm về TP.HCM. Điều khu tây còn thiếu lúc này không chỉ là nhà ở, mà là một "lõi sống" đủ mạnh để giữ sức mua ở lại.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/20/1-1773987897007418167184-0-30-688-1131-crop-17739881523641217274825.jpg', NULL, '2026-03-20 07:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm", "link": "https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm", "title": "Khu t&acirc;y TP.HCM: D&ograve;ng tiền đổ về mạnh, nhưng sức mua vẫn dồn v&agrave;o trung t&acirc;m", "content": "<a href=\"https://thanhnien.vn/khu-tay-tphcm-dong-tien-do-ve-manh-nhung-suc-mua-van-don-vao-trung-tam-185260320133339634.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/20/1-1773987897007418167184-0-30-688-1131-crop-17739881523641217274825.jpg\"></a> Bến Lức đang tăng trưởng nhanh nhờ hạ tầng, c&ocirc;ng nghiệp v&agrave; d&acirc;n cư dịch chuyển. Nhưng khi cần mua sắm, giải tr&iacute; hay tận hưởng cuối tuần, nhiều người vẫn t&igrave;m về TP.HCM. Điều khu t&acirc;y c&ograve;n thiếu l&uacute;c n&agrave;y kh&ocirc;ng chỉ l&agrave; nh&agrave; ở, m&agrave; l&agrave; một &quot;l&otilde;i sống&quot; đủ mạnh để giữ sức mua ở lại.", "isoDate": "2026-03-20T07:00:00.000Z", "pubDate": "Fri, 20 Mar 26 14:00:00 +0700", "contentSnippet": "Bến Lức đang tăng trưởng nhanh nhờ hạ tầng, công nghiệp và dân cư dịch chuyển. Nhưng khi cần mua sắm, giải trí hay tận hưởng cuối tuần, nhiều người vẫn tìm về TP.HCM. Điều khu tây còn thiếu lúc này không chỉ là nhà ở, mà là một \"lõi sống\" đủ mạnh để giữ sức mua ở lại."}', '2026-04-05 15:13:22.016625+00', '2026-04-05 15:39:58.500054+00', '2026-04-06 15:25:44.335017+00', '2026-04-06 15:25:44.335017+00', 1, NULL, NULL, NULL);
