INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (877, 21, 'https://cafef.vn/quoc-cuong-gia-lai-bi-nghi-ngo-kha-nang-hoat-dong-188260404203814425.chn', 'https://cafef.vn/quoc-cuong-gia-lai-bi-nghi-ngo-kha-nang-hoat-dong-188260404203814425.chn', 'Quốc Cường Gia Lai bị nghi ngờ khả năng hoạt động', '<a href="https://cafef.vn/quoc-cuong-gia-lai-bi-nghi-ngo-kha-nang-hoat-dong-188260404203814425.chn"><img src="https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/4/avatar1775309840765-177530984110488011368.webp"></a> Tính đến cuối năm 2025, tổng tài sản ngắn hạn của Quốc Cường Gia Lai đạt khoảng hơn 2.240 tỷ đồng, trong khi nợ ngắn hạn lên tới hơn 3.920 tỷ đồng. Khoản chênh lệch lớn này chủ yếu đến từ nghĩa vụ hoàn trả hơn 1.680 tỷ đồng liên quan đến dự án Khu dân cư Bắc Phước Kiển, nhằm đảm bảo thi hành án trong vụ án liên quan đến bà Trương Mỹ Lan.', 'Tính đến cuối năm 2025, tổng tài sản ngắn hạn của Quốc Cường Gia Lai đạt khoảng hơn 2.240 tỷ đồng, trong khi nợ ngắn hạn lên tới hơn 3.920 tỷ đồng. Khoản chênh lệch lớn này chủ yếu đến từ nghĩa vụ hoàn trả hơn 1.680 tỷ đồng liên quan đến dự án Khu dân cư Bắc Phước Kiển, nhằm đảm bảo thi hành án trong vụ án liên quan đến bà Trương Mỹ Lan.', 'https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/4/avatar1775309840765-177530984110488011368.webp', NULL, '2026-04-04 13:38:00+00', 'Thị trường chứng khoán | cafef', 'https://cafef.vn/thi-truong-chung-khoan.chn', '{"guid": "https://cafef.vn/quoc-cuong-gia-lai-bi-nghi-ngo-kha-nang-hoat-dong-188260404203814425.chn", "link": "https://cafef.vn/quoc-cuong-gia-lai-bi-nghi-ngo-kha-nang-hoat-dong-188260404203814425.chn", "title": "Quốc Cường Gia Lai bị nghi ngờ khả năng hoạt động", "content": "<a href=\"http