INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (172, 4, 'https://thanhnien.vn/cong-ty-hat-nhan-tap-doan-ttc-dang-ky-ban-ra-hon-43-trieu-co-phieu-sbt-185260323111601924.htm', 'https://thanhnien.vn/cong-ty-hat-nhan-tap-doan-ttc-dang-ky-ban-ra-hon-43-trieu-co-phieu-sbt-185260323111601924.htm', 'Công ty hạt nhân Tập đoàn TTC đăng ký bán ra hơn 43 triệu cổ phiếu SBT', '<a href="https://thanhnien.vn/cong-ty-hat-nhan-tap-doan-ttc-dang-ky-ban-ra-hon-43-trieu-co-phieu-sbt-185260323111601924.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/23/vung-nguyen-lieu-17742391718782089157893-0-181-1012-1800-crop-1774239245022179845204.jpg"></a> Ng&agrave;y 20.3.2026, CTCP Đầu tư Th&agrave;nh Th&agrave;nh C&ocirc;ng đ&atilde; th&ocirc;ng b&aacute;o đăng k&yacute; b&aacute;n hơn 43,8 triệu cổ phiếu SBT. Đ&acirc;y l&agrave; m&atilde; chứng kho&aacute;n của CTCP Th&agrave;nh Th&agrave;nh C&ocirc;ng - Bi&ecirc;n H&ograve;a (TTC AgriS, HOSE: SBT).', 'Ngày 20.3.2026, CTCP Đầu tư Thành Thành Công đã thông báo đăng ký bán hơn 43,8 triệu cổ phiếu SBT. Đây là mã chứng khoán của CTCP Thành Thành Công - Biên Hòa (TTC AgriS, HOSE: SBT).', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/23/vung-nguyen-lieu-17742391718782089157893-0-181-1012-1800-crop-1774239245022179845204.jpg', NULL, '2026-03-23 04:10:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/cong-ty-hat-nhan-tap-doan-ttc-dang-ky-ban-ra-hon-43-trieu-co-phieu-sbt-185260323111601924.htm", "link": "https://thanhnien.vn/cong-ty-hat-nhan-tap-doan-ttc-dang-ky-ban-ra-hon-43-trieu-co-phieu-sbt-185260323111601924.htm", "title": "C&ocirc;ng ty hạt nh&acir