INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (177, 4, 'https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm', 'https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm', 'Doanh nghiệp hải sản Na Uy hợp tác khai mở thị trường cá hồi tại Việt Nam', '<a href="https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/1-17741509437311047237234-34-0-909-1400-crop-17741509671041778492027.jpg"></a> Việt Nam đang nổi l&ecirc;n l&agrave; một trong những thị trường tăng trưởng quan trọng cho c&aacute; hồi Na Uy tại khu vực Đ&ocirc;ng Nam &Aacute;. Thu nhập ng&agrave;y c&agrave;ng tăng, sự mở rộng nhanh của hệ thống b&aacute;n lẻ hiện đại v&agrave; dịch vụ ăn uống, c&ugrave;ng xu hướng ti&ecirc;u d&ugrave;ng ưu ti&ecirc;n c&aacute;c sản phẩm thực phẩm nhập khẩu chất lượng cao đang tạo nền tảng vững chắc cho sự ph&aacute;t triển của ng&agrave;nh h&agrave;ng n&agrave;y.', 'Việt Nam đang nổi lên là một trong những thị trường tăng trưởng quan trọng cho cá hồi Na Uy tại khu vực Đông Nam Á. Thu nhập ngày càng tăng, sự mở rộng nhanh của hệ thống bán lẻ hiện đại và dịch vụ ăn uống, cùng xu hướng tiêu dùng ưu tiên các sản phẩm thực phẩm nhập khẩu chất lượng cao đang tạo nền tảng vững chắc cho sự phát triển của ngành hàng này.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/1-17741509437311047237234-34-0-909-1400-crop-17741509671041778492027.jpg', NULL, '2026-03-23 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm", "link": "https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm", "title": "Doanh nghiệp hải sản Na Uy hợp t&aacute;c khai mở thị trường c&aacute; hồi tại Việt Nam", "content": "<a href=\"https://thanhnien.vn/doanh-nghiep-hai-san-na-uy-hop-tac-khai-mo-thi-truong-ca-hoi-tai-viet-nam-185260322105115143.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/1-17741509437311047237234-34-0-909-1400-crop-17741509671041778492027.jpg\"></a> Việt Nam đang nổi l&ecirc;n l&agrave; một trong những thị trường tăng trưởng quan trọng cho c&aacute; hồi Na Uy tại khu vực Đ&ocirc;ng Nam &Aacute;. Thu nhập ng&agrave;y c&agrave;ng tăng, sự mở rộng nhanh của hệ thống b&aacute;n lẻ hiện đại v&agrave; dịch vụ ăn uống, c&ugrave;ng xu hướng ti&ecirc;u d&ugrave;ng ưu ti&ecirc;n c&aacute;c sản phẩm thực phẩm nhập khẩu chất lượng cao đang tạo nền tảng vững chắc cho sự ph&aacute;t triển của ng&agrave;nh h&agrave;ng n&agrave;y.", "isoDate": "2026-03-23T01:00:00.000Z", "pubDate": "Mon, 23 Mar 26 08:00:00 +0700", "contentSnippet": "Việt Nam đang nổi lên là một trong những thị trường tăng trưởng quan trọng cho cá hồi Na Uy tại khu vực Đông Nam Á. Thu nhập ngày càng tăng, sự mở rộng nhanh của hệ thống bán lẻ hiện đại và dịch vụ ăn uống, cùng xu hướng tiêu dùng ưu tiên các sản phẩm thực phẩm nhập khẩu chất lượng cao đang tạo nền tảng vững chắc cho sự phát triển của ngành hàng này."}', '2026-04-05 15:13:22.008408+00', '2026-04-07 05:10:47.73026+00', '2026-04-06 15:25:44.335017+00', '2026-04-07 05:10:47.73026+00', 3, NULL, NULL, NULL);
