INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (176, 4, 'https://thanhnien.vn/bidv-metlife-tham-gia-trong-650-cay-xanh-tai-dai-hoc-quoc-gia-ha-noi-185260322150120406.htm', 'https://thanhnien.vn/bidv-metlife-tham-gia-trong-650-cay-xanh-tai-dai-hoc-quoc-gia-ha-noi-185260322150120406.htm', 'BIDV MetLife tham gia trồng 650 cây xanh tại Đại học Quốc gia Hà Nội', '<a href="https://thanhnien.vn/bidv-metlife-tham-gia-trong-650-cay-xanh-tai-dai-hoc-quoc-gia-ha-noi-185260322150120406.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/2-17741661444431108830195-0-0-875-1400-crop-1774166209685248011975.jpg"></a> Với mong muốn g&oacute;p phần lan tỏa lối sống bền vững v&agrave; n&acirc;ng cao nhận thức về bảo vệ m&ocirc;i trường cho thế hệ trẻ, BIDV MetLife đ&atilde; tham gia chương tr&igrave;nh trồng 650 c&acirc;y xanh trong khu&ocirc;n vi&ecirc;n Đại học Quốc gia H&agrave; Nội. Hoạt động nằm trong s&aacute;ng kiến do MetLife Foundation t&agrave;i trợ, hướng tới x&acirc;y dựng kh&ocirc;ng gian học đường xanh v&agrave; th&uacute;c đẩy ph&aacute;t triển bền vững trong cộng đồng.', 'Với mong muốn góp phần lan tỏa lối sống bền vững và nâng cao nhận thức về bảo vệ môi trường cho thế hệ trẻ, BIDV MetLife đã tham gia chương trình trồng 650 cây xanh trong khuôn viên Đại học Quốc gia Hà Nội. Hoạt động nằm trong sáng kiến do MetLife Foundation tài trợ, hướng tới xây dựng không gian học đường xanh và thúc đẩy phát triển bền vững trong cộng đồng.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/2-17741661444431108830195-0-0-875-1400-crop-1774166209685248011975.jpg', NULL, '2026-03-23 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/d