INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1826, 59, 'https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn', 'https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn', 'Vì sao giá vàng thế giới giảm, trong nước tăng?', '<a href="https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775368105498-17753681058562052465705.webp"></a> Cục Thống kê cho biết, dù giá vàng thế giới giảm, chỉ số giá vàng tháng 3 vẫn tăng 1,54% so với tháng trước. Nguyên nhân chủ yếu do giá vàng được các doanh nghiệp kinh doanh điều chỉnh tăng, trong bối cảnh cung - cầu thị trường trong nước và yếu tố tâm lý nhà đầu tư.', 'Cục Thống kê cho biết, dù giá vàng thế giới giảm, chỉ số giá vàng tháng 3 vẫn tăng 1,54% so với tháng trước. Nguyên nhân chủ yếu do giá vàng được các doanh nghiệp kinh doanh điều chỉnh tăng, trong bối cảnh cung - cầu thị trường trong nước và yếu tố tâm lý nhà đầu tư.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775368105498-17753681058562052465705.webp', NULL, '2026-04-05 07:22:00+00', 'Kinh doanh | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh.chn', '{"guid": "https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn", "link": "https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn", "title": "Vì sao giá vàng thế giới giảm, trong nước tăng?", "content": "<a href=\"https://cafebiz.vn/vi-sao-gia-vang-the-gioi-giam-trong-nuoc-tang-176260405124908331.chn\"><img src=\"https://cafebiz.cafebizcdn.vn/zoom/700_438/1