INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (493, 4, 'https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm', 'https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm', 'Go Green Go Up: Mỗi giao dịch tại Vietcap đều góp phần ‘xanh rừng, chắn lũ’', '<a href="https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/6/1-17754377827861743805935-32-0-970-1500-crop-17754382530132132580027.jpg"></a> Th&aacute;ng 4.2026, sau m&ugrave;a đầu ti&ecirc;n triển khai th&agrave;nh c&ocirc;ng, C&ocirc;ng ty Chứng kho&aacute;n Vietcap tiếp tục thực hiện chương tr&igrave;nh Go Green Go Up 2026 với th&ocirc;ng điệp &#039;Chung tay xanh rừng - Vững th&ecirc;m chắn lũ&#039;, khẳng định vị thế ti&ecirc;n phong trong việc t&iacute;ch hợp t&agrave;i ch&iacute;nh xanh v&agrave;o trải nghiệm đầu tư, đ&oacute;ng g&oacute;p thiết thực v&agrave;o ph&aacute;t triển bền vững của cộng đồng v&agrave; hệ sinh th&aacute;i xanh Việt Nam.', 'Tháng 4.2026, sau mùa đầu tiên triển khai thành công, Công ty Chứng khoán Vietcap tiếp tục thực hiện chương trình Go Green Go Up 2026 với thông điệp ''Chung tay xanh rừng - Vững thêm chắn lũ'', khẳng định vị thế tiên phong trong việc tích hợp tài chính xanh vào trải nghiệm đầu tư, đóng góp thiết thực vào phát triển bền vững của cộng đồng và hệ sinh thái xanh Việt Nam.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/6/1-17754377827861743805935-32-0-970-1500-crop-17754382530132132580027.jpg', NULL, '2026-04-06 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm", "link": "https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm", "title": "Go Green Go Up: Mỗi giao dịch tại Vietcap đều g&oacute;p phần &lsquo;xanh rừng, chắn lũ&rsquo;", "content": "<a href=\"https://thanhnien.vn/go-green-go-up-moi-giao-dich-tai-vietcap-deu-gop-phan-xanh-rung-chan-lu-185260406080508986.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/6/1-17754377827861743805935-32-0-970-1500-crop-17754382530132132580027.jpg\"></a> Th&aacute;ng 4.2026, sau m&ugrave;a đầu ti&ecirc;n triển khai th&agrave;nh c&ocirc;ng, C&ocirc;ng ty Chứng kho&aacute;n Vietcap tiếp tục thực hiện chương tr&igrave;nh Go Green Go Up 2026 với th&ocirc;ng điệp &#039;Chung tay xanh rừng - Vững th&ecirc;m chắn lũ&#039;, khẳng định vị thế ti&ecirc;n phong trong việc t&iacute;ch hợp t&agrave;i ch&iacute;nh xanh v&agrave;o trải nghiệm đầu tư, đ&oacute;ng g&oacute;p thiết thực v&agrave;o ph&aacute;t triển bền vững của cộng đồng v&agrave; hệ sinh th&aacute;i xanh Việt Nam.", "isoDate": "2026-04-06T01:00:00.000Z", "pubDate": "Mon, 06 Apr 26 08:00:00 +0700", "contentSnippet": "Tháng 4.2026, sau mùa đầu tiên triển khai thành công, Công ty Chứng khoán Vietcap tiếp tục thực hiện chương trình Go Green Go Up 2026 với thông điệp ''Chung tay xanh rừng - Vững thêm chắn lũ'', khẳng định vị thế tiên phong trong việc tích hợp tài chính xanh vào trải nghiệm đầu tư, đóng góp thiết thực vào phát triển bền vững của cộng đồng và hệ sinh thái xanh Việt Nam."}', '2026-04-06 13:18:16.199424+00', '2026-04-08 14:21:49.681606+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.681606+00', 7, 'c778916b2a519a4b32dfc8e3d4d8a5c33d767eae878de5671825ab43cc3f32c9', '2026-04-07 15:01:35.114078+00', 'ai-ner');
