INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (134, 4, 'https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm', 'https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm', 'TÜV SÜD Rail GmbH (Đức) sẽ kiểm định chất lượng ray đường sắt của Hòa Phát', '<a href="https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/tuv-sud-tu-van-quy-trinh-quan-ly-chat-luong-va-cap-chung-nhan-san-pham-ray-duong-sat-cua-hoa-phat-1775136277644947307659-0-0-1578-2525-crop-1775136334534859804322.jpg"></a> Tập đo&agrave;n H&ograve;a Ph&aacute;t h&ocirc;m nay (2.4) ch&iacute;nh thức k&yacute; kết hợp đồng với T&Uuml;V S&Uuml;D Rail GmbH (Đức) - tổ chức quốc tế uy t&iacute;n trong lĩnh vực thử nghiệm, kiểm định v&agrave; chứng nhận đường sắt. Sự kiện đ&aacute;nh dấu một bước tiến quan trọng trong chiến lược ph&aacute;t triển sản phẩm th&eacute;p ray chất lượng cao của H&ograve;a Ph&aacute;t, đ&aacute;p ứng c&aacute;c y&ecirc;u cầu kỹ thuật khắt khe của ng&agrave;nh đường sắt hiện đại.', 'Tập đoàn Hòa Phát hôm nay (2.4) chính thức ký kết hợp đồng với TÜV SÜD Rail GmbH (Đức) - tổ chức quốc tế uy tín trong lĩnh vực thử nghiệm, kiểm định và chứng nhận đường sắt. Sự kiện đánh dấu một bước tiến quan trọng trong chiến lược phát triển sản phẩm thép ray chất lượng cao của Hòa Phát, đáp ứng các yêu cầu kỹ thuật khắt khe của ngành đường sắt hiện đại.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/tuv-sud-tu-van-quy-trinh-quan-ly-chat-luong-va-cap-chung-nhan-san-pham-ray-duong-sat-cua-hoa-phat-1775136277644947307659-0-0-1578-2525-crop-1775136334534859804322.jpg', NULL, '2026-04-02 13:37:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm", "link": "https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm", "title": "T&Uuml;V S&Uuml;D Rail GmbH (Đức) sẽ kiểm định chất lượng ray đường sắt của H&ograve;a Ph&aacute;t", "content": "<a href=\"https://thanhnien.vn/tv-sd-rail-gmbh-duc-se-kiem-dinh-chat-luong-ray-duong-sat-cua-hoa-phat-185260402202611521.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/tuv-sud-tu-van-quy-trinh-quan-ly-chat-luong-va-cap-chung-nhan-san-pham-ray-duong-sat-cua-hoa-phat-1775136277644947307659-0-0-1578-2525-crop-1775136334534859804322.jpg\"></a> Tập đo&agrave;n H&ograve;a Ph&aacute;t h&ocirc;m nay (2.4) ch&iacute;nh thức k&yacute; kết hợp đồng với T&Uuml;V S&Uuml;D Rail GmbH (Đức) - tổ chức quốc tế uy t&iacute;n trong lĩnh vực thử nghiệm, kiểm định v&agrave; chứng nhận đường sắt. Sự kiện đ&aacute;nh dấu một bước tiến quan trọng trong chiến lược ph&aacute;t triển sản phẩm th&eacute;p ray chất lượng cao của H&ograve;a Ph&aacute;t, đ&aacute;p ứng c&aacute;c y&ecirc;u cầu kỹ thuật khắt khe của ng&agrave;nh đường sắt hiện đại.", "isoDate": "2026-04-02T13:37:00.000Z", "pubDate": "Thu, 02 Apr 26 20:37:00 +0700", "contentSnippet": "Tập đoàn Hòa Phát hôm nay (2.4) chính thức ký kết hợp đồng với TÜV SÜD Rail GmbH (Đức) - tổ chức quốc tế uy tín trong lĩnh vực thử nghiệm, kiểm định và chứng nhận đường sắt. Sự kiện đánh dấu một bước tiến quan trọng trong chiến lược phát triển sản phẩm thép ray chất lượng cao của Hòa Phát, đáp ứng các yêu cầu kỹ thuật khắt khe của ngành đường sắt hiện đại."}', '2026-04-05 15:13:21.887529+00', '2026-04-08 14:21:49.690131+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.690131+00', 7, '6768bf327f0c2852a2d4fa87abe1704edf1d12e11bcfc1ead651b13235978261', '2026-04-07 15:01:36.018646+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (173, 4, 'https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm', 'https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm', 'Vì sao bầu Đức ''rẽ ngang'' sang cà phê?', '<a href="https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/nik-1462a-17741872374331027989123-0-0-1248-1997-crop-17741872509581352815539.jpg"></a> D&ugrave; chuối v&agrave; sầu ri&ecirc;ng mang lại lợi nhuận h&agrave;ng ng&agrave;n tỉ đồng mỗi năm, bầu Đức đột ngột c&ocirc;ng bố &quot;Chiến lược ph&aacute;t triển bền vững 20.000 hecta c&agrave; ph&ecirc; tới năm 2028&quot;, đưa Ho&agrave;ng Anh Gia Lai trở th&agrave;nh doanh nghiệp sở hữu v&ugrave;ng trồng trực tiếp lớn nhất thế giới. Điều g&igrave; khiến bầu Đức thay v&igrave; nghỉ ngơi, hưởng thụ th&agrave;nh quả sau 1 thập kỉ c&agrave;y trả nợ lại lao v&agrave;o đường đua mới? ', 'Dù chuối và sầu riêng mang lại lợi nhuận hàng ngàn tỉ đồng mỗi năm, bầu Đức đột ngột công bố "Chiến lược phát triển bền vững 20.000 hecta cà phê tới năm 2028", đưa Hoàng Anh Gia Lai trở thành doanh nghiệp sở hữu vùng trồng trực tiếp lớn nhất thế giới. Điều gì khiến bầu Đức thay vì nghỉ ngơi, hưởng thụ thành quả sau 1 thập kỉ cày trả nợ lại lao vào đường đua mới?', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/nik-1462a-17741872374331027989123-0-0-1248-1997-crop-17741872509581352815539.jpg', NULL, '2026-03-23 01:21:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm", "link": "https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm", "title": "V&igrave; sao bầu Đức &#039;rẽ ngang&#039; sang c&agrave; ph&ecirc;?", "content": "<a href=\"https://thanhnien.vn/vi-sao-bau-duc-re-ngang-sang-ca-phe-185260322202022482.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/22/nik-1462a-17741872374331027989123-0-0-1248-1997-crop-17741872509581352815539.jpg\"></a> D&ugrave; chuối v&agrave; sầu ri&ecirc;ng mang lại lợi nhuận h&agrave;ng ng&agrave;n tỉ đồng mỗi năm, bầu Đức đột ngột c&ocirc;ng bố &quot;Chiến lược ph&aacute;t triển bền vững 20.000 hecta c&agrave; ph&ecirc; tới năm 2028&quot;, đưa Ho&agrave;ng Anh Gia Lai trở th&agrave;nh doanh nghiệp sở hữu v&ugrave;ng trồng trực tiếp lớn nhất thế giới. Điều g&igrave; khiến bầu Đức thay v&igrave; nghỉ ngơi, hưởng thụ th&agrave;nh quả sau 1 thập kỉ c&agrave;y trả nợ lại lao v&agrave;o đường đua mới? ", "isoDate": "2026-03-23T01:21:00.000Z", "pubDate": "Mon, 23 Mar 26 08:21:00 +0700", "contentSnippet": "Dù chuối và sầu riêng mang lại lợi nhuận hàng ngàn tỉ đồng mỗi năm, bầu Đức đột ngột công bố \"Chiến lược phát triển bền vững 20.000 hecta cà phê tới năm 2028\", đưa Hoàng Anh Gia Lai trở thành doanh nghiệp sở hữu vùng trồng trực tiếp lớn nhất thế giới. Điều gì khiến bầu Đức thay vì nghỉ ngơi, hưởng thụ thành quả sau 1 thập kỉ cày trả nợ lại lao vào đường đua mới?"}', '2026-04-05 15:13:21.998162+00', '2026-04-07 16:14:52.645634+00', '2026-04-06 15:25:44.335017+00', '2026-04-07 16:14:52.645634+00', 6, '2810d4e7996856535a094c71eb149fe3d8928ef3cd02cb95782ca38a238ad2bf', '2026-04-07 15:01:46.546401+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1583, 29, 'https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html', 'https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html', 'Google nâng cấp Vids, đẩy mạnh công cụ video AI', '<a href="https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html"><img width="180" height="120" src="https://image.bnews.vn/MediaUpload/Medium/2024/11/26/150717-chinh-phu-my-de-nghi-google-ban-trinh-duyet-chrome.jpg"/></a>Google bổ sung loạt tính năng AI cho Vids, từ tạo video, điều khiển avatar đến xuất YouTube, nhằm tăng cạnh tranh và mở rộng hệ sinh thái sáng tạo nội dung số.<br/>', 'Google bổ sung loạt tính năng AI cho Vids, từ tạo video, điều khiển avatar đến xuất YouTube, nhằm tăng cạnh tranh và mở rộng hệ sinh thái sáng tạo nội dung số.', 'https://image.bnews.vn/MediaUpload/Medium/2024/11/26/150717-chinh-phu-my-de-nghi-google-ban-trinh-duyet-chrome.jpg', NULL, '2026-04-03 01:42:52+00', 'Doanh nghiệp - Bnews.vn RSS', 'https://bnews.vn/rss/doanh-nghiep-6.rss', '{"guid": "https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html", "link": "https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html", "title": "Google nâng cấp Vids, đẩy mạnh công cụ video AI", "content": "<a href=\"https://bnews.vn/google-nang-cap-vids-day-manh-cong-cu-video-ai/416070.html\"><img width=\"180\" height=\"120\" src=\"https://image.bnews.vn/MediaUpload/Medium/2024/11/26/150717-chinh-phu-my-de-nghi-google-ban-trinh-duyet-chrome.jpg\"/></a>Google bổ sung loạt tính năng AI cho Vids, từ tạo video, điều khiển avatar đến xuất YouTube, nhằm tăng cạnh tranh và mở rộng hệ sinh thái sáng tạo nội dung số.<br