INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (135, 4, 'https://thanhnien.vn/chien-luoc-quan-tri-hinh-anh-y-te-so-tap-trung-cho-mo-hinh-da-co-so-185260402150320341.htm', 'https://thanhnien.vn/chien-luoc-quan-tri-hinh-anh-y-te-so-tap-trung-cho-mo-hinh-da-co-so-185260402150320341.htm', 'Chiến lược quản trị hình ảnh y tế số tập trung cho mô hình đa cơ sở', '<a href="https://thanhnien.vn/chien-luoc-quan-tri-hinh-anh-y-te-so-tap-trung-cho-mo-hinh-da-co-so-185260402150320341.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/3/moc-signing-1775204630455270290417-107-0-1707-2560-crop-1775204765150594443087.jpg"></a> Trong bối cảnh chuyển đổi số y tế, Fujifilm Việt Nam k&yacute; kết hợp t&aacute;c chiến lược với J.F. Advance Med, đơn vị hơn 25 năm triển khai Synapse Enterprise Imaging - giải ph&aacute;p quản trị h&igrave;nh ảnh y tế to&agrave;n diện đ&atilde; triển khai hơn 7.500 cơ sở y tế to&agrave;n cầu, hứa hẹn n&acirc;ng tầm quản trị y tế số tại Việt Nam.', 'Trong bối cảnh chuyển đổi số y tế, Fujifilm Việt Nam ký kết hợp tác chiến lược với J.F. Advance Med, đơn vị hơn 25 năm triển khai Synapse Enterprise Imaging - giải pháp quản trị hình ảnh y tế toàn diện đã triển khai hơn 7.500 cơ sở y tế toàn cầu, hứa hẹn nâng tầm quản trị y tế số tại Việt Nam.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/3/moc-signing-1775204630455270290417-107-0-1707-2560-crop-1775204765150594443087.jpg', NULL, '2026-04-02 13:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/chien-luoc-quan-tri-hinh-anh-y-te-so-tap-trung-cho-mo-hinh-da-co-so-185260402150320341.htm", "link": "https://thanhnien.vn/