INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (171, 4, 'https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm', 'https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm', 'EU bắt buộc bao bì hàng hóa phải sử dụng nhựa tái chế', '<a href="https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/23/2b8e02273b8fb5d1ec9e-17742489884961443780857-160-0-960-1280-crop-1774249168933552848842.jpg"></a> Bao b&igrave; h&agrave;ng h&oacute;a, kể cả thực phẩm, lưu th&ocirc;ng ở thị trường EU bắt buộc phải c&oacute; tỷ lệ nhựa t&aacute;i chế (Recycled Content) nhất định. Đ&acirc;y l&agrave; một trong những quy định mới của ch&acirc;u &Acirc;u về bao b&igrave; v&agrave; r&aacute;c thải bao b&igrave;.', 'Bao bì hàng hóa, kể cả thực phẩm, lưu thông ở thị trường EU bắt buộc phải có tỷ lệ nhựa tái chế (Recycled Content) nhất định. Đây là một trong những quy định mới của châu Âu về bao bì và rác thải bao bì.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/23/2b8e02273b8fb5d1ec9e-17742489884961443780857-160-0-960-1280-crop-1774249168933552848842.jpg', NULL, '2026-03-23 07:06:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm", "link": "https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm", "title": "EU bắt buộc bao b&igrave; h&agrave;ng h&oacute;a phải sử dụng nhựa t&aacute;i chế", "content": "<a href=\"https://thanhnien.vn/eu-bat-buoc-bao-bi-hang-hoa-phai-su-dung-nhua-tai-che-1852603231400505.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/23/2b8e02273b8fb5d1ec9e-17742489884961443780857-160-0-960-1280-crop-1774249168933552848842.jpg\"></a> Bao b&igrave; h&agrave;ng h&oacute;a, kể cả thực phẩm, lưu th&ocirc;ng ở thị trường EU bắt buộc phải c&oacute; tỷ lệ nhựa t&aacute;i chế (Recycled Content) nhất định. Đ&acirc;y l&agrave; một trong những quy định mới của ch&acirc;u &Acirc;u về bao b&igrave; v&agrave; r&aacute;c thải bao b&igrave;.", "isoDate": "2026-03-23T07:06:00.000Z", "pubDate": "Mon, 23 Mar 26 14:06:00 +0700", "contentSnippet": "Bao bì hàng hóa, kể cả thực phẩm, lưu thông ở thị trường EU bắt buộc phải có tỷ lệ nhựa tái chế (Recycled Content) nhất định. Đây là một trong những quy định mới của châu Âu về bao bì và rác thải bao bì."}', '2026-04-05 15:13:21.993375+00', '2026-04-07 16:14:52.630566+00', '2026-04-06 15:25:44.335017+00', '2026-04-07 16:14:52.630566+00', 6, '10d867cf4d20a4cb337d5f8f4189d06c22deb08d271112afe1f112021ec65997', '2026-04-07 15:01:46.359843+00', 'ai-ner');
