INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1827, 59, 'https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn', 'https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn', 'Cổ phiếu Novaland vừa ''thoát hiểm'' thế nào?', '<a href="https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775367901195-17753679018501391743294.webp"></a> Cổ phiếu NVL của Tập đoàn Novaland không còn xuất hiện trong danh sách bị cắt margin. Lần gần nhất mã chứng khoán NVL bị cắt margin là do chậm nộp báo cáo tài chính soát xét bán niên 2024 và kéo dài cho đến nay.', 'Cổ phiếu NVL của Tập đoàn Novaland không còn xuất hiện trong danh sách bị cắt margin. Lần gần nhất mã chứng khoán NVL bị cắt margin là do chậm nộp báo cáo tài chính soát xét bán niên 2024 và kéo dài cho đến nay.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775367901195-17753679018501391743294.webp', NULL, '2026-04-05 07:22:00+00', 'Kinh doanh | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh.chn', '{"guid": "https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn", "link": "https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn", "title": "Cổ phiếu Novaland vừa ''thoát hiểm'' thế nào?", "content": "<a href=\"https://cafebiz.vn/co-phieu-novaland-vua-thoat-hiem-the-nao-176260405124658838.chn\"><img src=\"https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775367901195-17753679018501391743294.webp\"></a> Cổ phiếu NVL của Tập đoàn Novaland không còn xuất hiện trong danh sách bị cắt margin. Lần gần nhất mã chứng khoán NVL bị cắt margin là do chậm nộp báo cáo tài chính soát xét bán niên 2024 và kéo dài cho đến nay.", "isoDate": "2026-04-05T07:22:00.000Z", "pubDate": "Sun, 05 Apr 2026 14:22:00 +07", "contentSnippet": "Cổ phiếu NVL của Tập đoàn Novaland không còn xuất hiện trong danh sách bị cắt margin. Lần gần nhất mã chứng khoán NVL bị cắt margin là do chậm nộp báo cáo tài chính soát xét bán niên 2024 và kéo dài cho đến nay."}', '2026-04-06 15:12:18.87325+00', '2026-04-06 15:26:04.272437+00', '2026-04-06 15:25:44.335017+00', '2026-04-06 15:26:04.272437+00', 2, NULL, NULL, NULL);
