INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1810, 59, 'https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn', 'https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn', 'Đại gia buôn ô tô dự kiến 2026 lãi tăng gấp 3 lần, đánh mạnh sang xe điện', '<a href="https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775432898536-1775432898816759458441.jpg"></a> Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025.', 'Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775432898536-1775432898816759458441.jpg', NULL, '2026-04-06 00:48:00+00', 'Kinh doanh | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh.chn', '{"guid": "https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn", "link": "https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn", "title": "Đại gia buôn ô tô dự kiến 2026 lãi tăng gấp 3 lần, đánh mạnh sang xe điện", "content": "<a href=\"https://cafebiz.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-176260406064904077.chn\"><img src=\"https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/5/avatar1775432898536-1775432898816759458441.jpg\"></a> Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025.", "isoDate": "2026-04-06T00:48:00.000Z", "pubDate": "Mon, 06 Apr 2026 07:48:00 +07", "contentSnippet": "Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025."}', '2026-04-06 15:12:18.813877+00', '2026-04-07 05:05:58.156567+00', '2026-04-06 15:25:44.335017+00', '2026-04-07 05:05:58.156567+00', 3, NULL, NULL, NULL);
