INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (2908, 3, 'http://vietstock.vn/2026/04/mot-co-phieu-ba-cau-chuyen-tang-truong-msn-dang-o-thoi-diem-nao-737-1423384.htm', 'http://vietstock.vn/2026/04/mot-co-phieu-ba-cau-chuyen-tang-truong-msn-dang-o-thoi-diem-nao-737-1423384.htm', 'Một cổ phiếu, ba câu chuyện tăng trưởng: MSN đang ở thời điểm nào?', '<img alt='''' width=''120'' height=''90'' src=''https://image.vietstock.vn/2026/04/06/msn-1_13721.jpg''/>Trong đầu tư, những cơ hội lớn nhất không đến từ một mảng kinh doanh đơn lẻ, mà xuất hiện khi nhiều động lực tăng trưởng cùng lúc hội tụ và bắt đầu vận hành đồng pha. Năm 2026, Masan Group (HOSE: MSN) đang bước vào một thời điểm như vậy, khi các mảng gồm bán lẻ, tiêu dùng và vật liệu công nghệ cao đồng thời bước qua một bước ngoặt quan trọng, mở ra khả năng định giá lại toàn bộ tập đoàn.', 'Trong đầu tư, những cơ hội lớn nhất không đến từ một mảng kinh doanh đơn lẻ, mà xuất hiện khi nhiều động lực tăng trưởng cùng lúc hội tụ và bắt đầu vận hành đồng pha. Năm 2026, Masan Group (HOSE: MSN) đang bước vào một thời điểm như vậy, khi các mảng gồm bán lẻ, tiêu dùng và vật liệu công nghệ cao đồng thời bước qua một bước ngoặt quan trọng, mở ra khả năng định giá lại toàn bộ tập đoàn.', 'https://image.vietstock.vn/2026/04/06/msn-1_13721.jpg', NULL, '2026-04-07 01:02:00+00', 'Hoạt động kinh doanh - Vietstock RSS', 'http://vietstock.vn/737/doanh-nghiep/hoat-dong-kinh-doanh.rss', '{"guid": "http://vietstock.vn/2026/04/mot-co-phieu-ba-cau-chuyen-tang-truong-msn-dang-o-thoi-diem-nao-737-1423384.htm", "link": "http://vietstock.vn/2026/04/mot-co-phieu-ba-cau-chuyen-tang-truong-msn-dang-o-thoi-diem-nao-737-1423384.htm", "title": "Một cổ phiếu, ba câu chuyện tăng trưởn