INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (2084, 33, 'https://baodautu.vn/hanel-va-chu-tich-hanel-duoc-vinh-danh-tai-dien-dan-hop-tac-kinh-te-chau-a-2025-d272080.html', 'https://baodautu.vn/hanel-va-chu-tich-hanel-duoc-vinh-danh-tai-dien-dan-hop-tac-kinh-te-chau-a-2025-d272080.html', 'Hanel và Chủ tịch Hanel được vinh danh tại Diễn đàn Hợp tác kinh tế châu Á 2025', 'Vừa qua, tại Diễn đàn hợp tác Kinh tế châu Á & Lễ công bố Thương hiệu Mạnh châu Á 2025 đã diễn ra tại Thượng Hải, Trung Quốc. CTCP Hanel và Chủ tịch HĐQT Hanel - bà Bùi Thị Hải Yến được vinh danh với danh hiệu Top 10 Thương hiệu mạnh châu Á và Nhà lãnh đạo doanh nghiệp giỏi châu Á tại sự kiện.', 'Vừa qua, tại Diễn đàn hợp tác Kinh tế châu Á & Lễ công bố Thương hiệu Mạnh châu Á 2025 đã diễn ra tại Thượng Hải, Trung Quốc. CTCP Hanel và Chủ tịch HĐQT Hanel - bà Bùi Thị Hải Yến được vinh danh với danh hiệu Top 10 Thương hiệu mạnh châu Á và Nhà lãnh đạo doanh nghiệp giỏi châu Á tại sự kiện.', 'https://media.baodautu.vn/thumb_x470x250/Images/chicong/2025/04/22/hanel-va-chu-tich-hanel-duoc-vinh-danh-tai-dien-dan-hop-tac-kinh-te-chau-a-20251745321915.jpeg', NULL, '2026-04-08 14:22:00.628+00', 'Doanh nhân', 'https://baodautu.vn//doanh-nhan.rss', '{"guid": "https://baodautu.vn/hanel-va-chu-tich-hanel-duoc-vinh-danh-tai-dien-dan-hop-tac-kinh-te-chau-a-2025-d272080.html", "link": "https://baodautu.vn/hanel-va-chu-tich-hanel-duoc-vinh-danh-tai-dien-dan-hop-tac-kinh-te-chau-a-2025-d272080.html", "title": "Hanel và Chủ tịch Hanel được vinh danh tại Diễn đàn Hợp tác kinh tế châu Á 2025", "content": "Vừa qua, tại Diễn đàn hợp tác Kinh tế châu Á & Lễ công bố Thương hiệu Mạnh châu Á 2025 đã diễn ra tại Thượng Hải, Trung Quốc. CTCP Hanel và Chủ tịc