INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (443, 2, 'https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-188260405231118868.chn', 'https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-188260405231118868.chn', 'Đại gia buôn ô tô dự kiến 2026 lãi tăng gấp 3 lần, đánh mạnh sang xe điện', '<a href="https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-188260405231118868.chn"><img src="https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/5/avatar1775405431588-17754054321241137659216.jpg"></a> Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025.', 'Bước sang năm 2026, TMT Motors đặt ra kế hoạch sản lượng tiêu thụ 26.766 chiếc tăng 500% so với thực hiện của 2025. Doanh thu thuần đạt 3.652 tỷ đồng, tăng 82,48%. Lợi nhuận sau thuế dự kiến 217 tỷ đồng, tăng 245% so với 2025.', 'https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/5/avatar1775405431588-17754054321241137659216.jpg', NULL, '2026-04-05 17:02:00+00', 'Doanh nghiệp | cafef', 'https://cafef.vn/doanh-nghiep.chn', '{"guid": "https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-188260405231118868.chn", "link": "https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-dien-188260405231118868.chn", "title": "Đại gia buôn ô tô dự kiến 2026 lãi tăng gấp 3 lần, đánh mạnh sang xe điện", "content": "<a href=\"https://cafef.vn/dai-gia-buon-o-to-du-kien-2026-lai-tang-gap-3-lan-danh-manh-sang-xe-d