INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (3227, 59, 'https://cafebiz.vn/mot-khi-fed-cat-giam-lai-suat-va-xung-dot-iran-ha-nhiet-tai-san-nay-du-kien-se-noi-lai-chuoi-tang-ky-luc-17626040713430704.chn', 'https://cafebiz.vn/mot-khi-fed-cat-giam-lai-suat-va-xung-dot-iran-ha-nhiet-tai-san-nay-du-kien-se-noi-lai-chuoi-tang-ky-luc-17626040713430704.chn', 'Một khi Fed cắt giảm lãi suất và xung đột Iran hạ nhiệt, tài sản này dự kiến sẽ nối lại chuỗi tăng kỷ lục', '<a href="https://cafebiz.vn/mot-khi-fed-cat-giam-lai-suat-va-xung-dot-iran-ha-nhiet-tai-san-nay-du-kien-se-noi-lai-chuoi-tang-ky-luc-17626040713430704.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/7/avatar1775544164580-17755441648011637771097.png"></a> Theo nhận định của các tổ chức tài chính toàn cầu, giá vàng được dự báo sẽ ổn định và nối lại xu hướng tăng kỷ lục khi căng thẳng Trung Đông hạ nhiệt và Cục Dự trữ Liên bang Mỹ (Fed) chuyển sang nới lỏng chính sách tiền tệ.', 'Theo nhận định của các tổ chức tài chính toàn cầu, giá vàng được dự báo sẽ ổn định và nối lại xu hướng tăng kỷ lục khi căng thẳng Trung Đông hạ nhiệt và Cục Dự trữ Liên bang Mỹ (Fed) chuyển sang nới lỏng chính sách tiền tệ.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/7/avatar1775544164580-17755441648011637771097.png', NULL, '2026-04-07 06:43:00+00', 'Kinh doanh | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh.chn', '{"guid": "https://cafebiz.vn/mot-khi-fed-cat-giam-lai-suat-va-xung-dot-iran-ha-nhiet-tai-san-nay-du-kien-se-noi-lai-chuoi-tang-ky-luc-17626040713430704.chn", "link": "https://cafebiz.vn/mot-khi-fed-cat-giam-lai-suat-va-xung-dot-iran-ha-nhiet-tai-san-nay-du-kien-se-noi-lai-chuoi-tang-