INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (485, 3, 'http://vietstock.vn/2026/04/seabank-du-kien-chia-co-tuc-205-tang-von-len-34688-ty-va-dat-muc-tieu-loi-nhuan-7068-ty-nam-2026-737-1423216.htm', 'http://vietstock.vn/2026/04/seabank-du-kien-chia-co-tuc-205-tang-von-len-34688-ty-va-dat-muc-tieu-loi-nhuan-7068-ty-nam-2026-737-1423216.htm', 'SeABank dự kiến chia cổ tức 20.5%, tăng vốn lên 34,688 tỷ và đặt mục tiêu lợi nhuận 7,068 tỷ năm 2026', '<img alt='''' width=''120'' height=''90'' src=''https://image.vietstock.vn/2026/04/06/ssb-ke-hoach-2026_932640.jpg''/>Ngân hàng TMCP Đông Nam Á (SeABank, HOSE: SSB) dự kiến tổ chức ĐHĐCĐ thường niên năm 2026 tại TP. Hải Phòng vào ngày 22/04/2026, trình cổ đông thông qua nhiều nội dung quan trọng như: phát hành cổ phiếu để trả cổ tức tỷ lệ 20.5% và phát hành ESOP từ đó tăng vốn điều lệ lên 34,688 tỷ đồng, bầu bổ sung thành viên BKS và kế hoạch lợi nhuận trước thuế năm 2026 đạt 7,068 tỷ đồng.', 'Ngân hàng TMCP Đông Nam Á (SeABank, HOSE: SSB) dự kiến tổ chức ĐHĐCĐ thường niên năm 2026 tại TP. Hải Phòng vào ngày 22/04/2026, trình cổ đông thông qua nhiều nội dung quan trọng như: phát hành cổ phiếu để trả cổ tức tỷ lệ 20.5% và phát hành ESOP từ đó tăng vốn điều lệ lên 34,688 tỷ đồng, bầu bổ sung thành viên BKS và kế hoạch lợi nhuận trước thuế năm 2026 đạt 7,068 tỷ đồng.', 'https://image.vietstock.vn/2026/04/06/ssb-ke-hoach-2026_932640.jpg', NULL, '2026-04-06 03:40:40+00', 'Hoạt động kinh doanh - Vietstock RSS', 'http://vietstock.vn/737/doanh-nghiep/hoat-dong-kinh-doanh.rss', '{"guid": "http://vietstock.vn/2026/04/seabank-du-kien-chia-co-tuc-205-tang-von-len-34688-ty-va-dat-muc-tieu-loi-nhuan-7068-ty-nam-2026-737-1423216.htm", "link": "http://vietstock.vn/2026/