INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (155, 4, 'https://thanhnien.vn/home-credit-loi-nhuan-sau-thue-dat-2076-ti-dong-nho-quan-tri-rui-ro-chat-che-185260327144448115.htm', 'https://thanhnien.vn/home-credit-loi-nhuan-sau-thue-dat-2076-ti-dong-nho-quan-tri-rui-ro-chat-che-185260327144448115.htm', 'Home Credit lợi nhuận sau thuế đạt 2.076 tỉ đồng nhờ quản trị rủi ro chặt chẽ', '<a href="https://thanhnien.vn/home-credit-loi-nhuan-sau-thue-dat-2076-ti-dong-nho-quan-tri-rui-ro-chat-che-185260327144448115.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/1-hinh-thumbnail-1774597314199989289343-42-0-1322-2048-crop-1774597402029563620042.png"></a> Năm 2025, Home Credit Việt Nam tiếp tục ghi nhận lợi nhuận đạt mốc kỷ lục mới. Doanh thu tăng, chi ph&iacute; được tối ưu v&agrave; nợ xấu được kiểm so&aacute;t l&agrave; động lực cho lợi nhuận của c&ocirc;ng ty. ', 'Năm 2025, Home Credit Việt Nam tiếp tục ghi nhận lợi nhuận đạt mốc kỷ lục mới. Doanh thu tăng, chi phí được tối ưu và nợ xấu được kiểm soát là động lực cho lợi nhuận của công ty.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/1-hinh-thumbnail-1774597314199989289343-42-0-1322-2048-crop-1774597402029563620042.png', NULL, '2026-03-27 07:36:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/home-credit-loi-nhuan-sau-thue-dat-2076-ti-dong-nho-quan-tri-rui-ro-chat-che-185260327144448115.htm", "link": "https://thanhnien.vn/home-credit-loi-nhuan-sau-thue-dat-2076-ti-dong-nho-quan-tri-rui-ro-chat-che-185260327144448115.htm", "title": "Home Credit lợi nhuận sau thuế đạt 2.076 tỉ đồng nhờ quản trị rủi ro chặt chẽ", "con