INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (61, 2, 'https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn', 'https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn', '"Thời hoàng kim" phòng gym cao cấp đến cuộc co hẹp lặng lẽ: Điều gì đang xảy ra với các chuỗi phòng gym lớn?', '<a href="https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn"><img src="https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/5/avatar1775400715441-17754007157911897066702.png"></a> Từng là biểu tượng của lối sống hiện đại, các chuỗi phòng gym quy mô lớn đang đối mặt với một thực tế khó tránh: lượng khách hàng hội viên dài hạn suy giảm, chi phí vận hành leo thang và sự cạnh tranh từ những mô hình thể thao linh hoạt hơn. Khi người dùng thay đổi cách tiếp cận với sức khỏe, từ "đi tập gym" sang "trải nghiệm vận động", ngành fitness bước vào một giai đoạn tái cấu trúc sâu sắc.', 'Từng là biểu tượng của lối sống hiện đại, các chuỗi phòng gym quy mô lớn đang đối mặt với một thực tế khó tránh: lượng khách hàng hội viên dài hạn suy giảm, chi phí vận hành leo thang và sự cạnh tranh từ những mô hình thể thao linh hoạt hơn. Khi người dùng thay đổi cách tiếp cận với sức khỏe, từ "đi tập gym" sang "trải nghiệm vận động", ngành fitness bước vào một giai đoạn tái cấu trúc sâu sắc.', 'https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/5/avatar1775400715441-17754007157911897066702.png', NULL, '2026-04-05 14:52:00+00', 'Doanh nghiệp | cafef', 'https://cafef.vn/doanh-nghiep.chn', '{"guid": "https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn", "link": "https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn", "title": "\"Thời hoàng kim\" phòng gym cao cấp đến cuộc co hẹp lặng lẽ: Điều gì đang xảy ra với các chuỗi phòng gym lớn?", "content": "<a href=\"https://cafef.vn/thoi-hoang-kim-phong-gym-cao-cap-den-cuoc-co-hep-lang-le-dieu-gi-dang-xay-ra-voi-cac-chuoi-phong-gym-lon-188260405215221891.chn\"><img src=\"https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/5/avatar1775400715441-17754007157911897066702.png\"></a> Từng là biểu tượng của lối sống hiện đại, các chuỗi phòng gym quy mô lớn đang đối mặt với một thực tế khó tránh: lượng khách hàng hội viên dài hạn suy giảm, chi phí vận hành leo thang và sự cạnh tranh từ những mô hình thể thao linh hoạt hơn. Khi người dùng thay đổi cách tiếp cận với sức khỏe, từ \"đi tập gym\" sang \"trải nghiệm vận động\", ngành fitness bước vào một giai đoạn tái cấu trúc sâu sắc.", "isoDate": "2026-04-05T14:52:00.000Z", "pubDate": "Sun, 05 Apr 26 21:52:00 +0700", "contentSnippet": "Từng là biểu tượng của lối sống hiện đại, các chuỗi phòng gym quy mô lớn đang đối mặt với một thực tế khó tránh: lượng khách hàng hội viên dài hạn suy giảm, chi phí vận hành leo thang và sự cạnh tranh từ những mô hình thể thao linh hoạt hơn. Khi người dùng thay đổi cách tiếp cận với sức khỏe, từ \"đi tập gym\" sang \"trải nghiệm vận động\", ngành fitness bước vào một giai đoạn tái cấu trúc sâu sắc."}', '2026-04-05 15:13:21.25662+00', '2026-04-07 16:14:49.574551+00', '2026-04-06 15:25:44.335017+00', '2026-04-07 16:14:49.574551+00', 6, 'a86c1812f92c2055503c631e2df2ffd192871ea71278e7d571ca56a6a9073542', '2026-04-07 14:58:58.333228+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (3419, 4, 'https://thanhnien.vn/kdi-holdings-10-nam-dinh-hinh-phat-trien-qua-3-truc-con-nguoi-trai-nghiem-ben-vung-185260407163819767.htm', 'https://thanhnien.vn/kdi-holdings-10-nam-dinh-hinh-phat-trien-qua-3-truc-con-nguoi-trai-nghiem-ben-vung-185260407163819767.htm', 'KDI Holdings 10 năm định hình phát triển qua 3 trục: Con người, trải nghiệm, bền vững', '<a href="https://thanhnien.vn/kdi-holdings-10-nam-dinh-hinh-phat-trien-qua-3-truc-con-nguoi-trai-nghiem-ben-vung-185260407163819767.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/7/h1-ban-lanh-dao-tap-toan-17755545497071576691294-0-0-1476-2362-crop-17755545780961441524491.jpg"></a> Kh&ocirc;ng chỉ l&agrave; dấu mốc kỷ niệm, chuỗi hoạt động 10 năm của KDI Holdings khẳng định chiến lược ph&aacute;t triển trong giai đoạn mới - nơi con người trở th&agrave;nh điểm chạm thương hiệu, trải nghiệm l&agrave; trung t&acirc;m v&agrave; yếu tố bền vững được đặt như một nguy&ecirc;n tắc cốt l&otilde;i trong to&agrave;n bộ hệ sinh th&aacute;i.', 'Không chỉ là dấu mốc kỷ niệm, chuỗi hoạt động 10 năm của KDI Holdings khẳng định chiến lược phát triển trong giai đoạn mới - nơi con người trở thành điểm chạm thương hiệu, trải nghiệm là trung tâm và yếu tố bền vững được đặt như một nguyên tắc cốt lõi trong toàn bộ hệ sinh thái.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/7/h1-ban-lanh-dao-tap-toan-17755545497071576691294-0-0-1476-2362-crop-17755545780961441524491.jpg', NULL, '2026-04-07 09:29:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/kdi-holdings-10-nam-dinh-hinh-phat-trien-qua