INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (17, 1, 'https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html', 'https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html', 'Doanh nghiệp dệt may ''gồng mình'' trước cú sốc Trung Đông', '<a href="https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html"><img src="https://i1-kinhdoanh.vnecdn.net/2026/04/03/233a2550-1775188644-5183-1775189635.jpg?w=1200&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=egyfGJs0KhKLU_WeERDpyw"></a></br>Chi phí đầu vào, logistics tăng mạnh sau biến cố Trung Đông, trong khi sức mua toàn cầu chậm, khiến doanh nghiệp dệt may mắc kẹt giữa chi phí và cạnh tranh với những thị trường lớn.', 'Chi phí đầu vào, logistics tăng mạnh sau biến cố Trung Đông, trong khi sức mua toàn cầu chậm, khiến doanh nghiệp dệt may mắc kẹt giữa chi phí và cạnh tranh với những thị trường lớn.', 'https://i1-kinhdoanh.vnecdn.net/2026/04/03/233a2550-1775188644-5183-1775189635.jpg?w=1200&h=0&q=100&dpr=1&fit=crop&s=egyfGJs0KhKLU_WeERDpyw', NULL, '2026-04-04 00:57:45+00', 'Kinh doanh - VnExpress RSS', 'https://vnexpress.net/rss/kinh-doanh.rss', '{"guid": "https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html", "link": "https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html", "title": "Doanh nghiệp dệt may ''gồng mình'' trước cú sốc Trung Đông", "content": "<a href=\"https://vnexpress.net/doanh-nghiep-det-may-gong-minh-truoc-cu-soc-trung-dong-5058029.html\"><img src=\"https://i1-kinhdoanh.vnecdn.net/2026/04/03/233a2550-1775188644-5183-1775189635.jpg?w=1200&amp;h=0&amp;q=100&amp;dpr=1&amp;