INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (136, 4, 'https://thanhnien.vn/tho-dien-may-xanh-khi-su-tan-tam-duoc-khang-dinh-qua-tay-nghe-chuan-hang-185260402191037749.htm', 'https://thanhnien.vn/tho-dien-may-xanh-khi-su-tan-tam-duoc-khang-dinh-qua-tay-nghe-chuan-hang-185260402191037749.htm', 'Thợ Điện Máy XANH: Khi sự tận tâm được khẳng định qua tay nghề chuẩn hãng', '<a href="https://thanhnien.vn/tho-dien-may-xanh-khi-su-tan-tam-duoc-khang-dinh-qua-tay-nghe-chuan-hang-185260402191037749.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/picture2-1775131687964365411971-52-0-927-1400-crop-17751317841951848054408.jpg"></a> Giữa bối cảnh thị trường dịch vụ lắp đặt vẫn c&ograve;n nhiều dư địa ph&aacute;t triển, Thợ Điện m&aacute;y XANH đang dần thiết lập một &#039;định nghĩa&#039; mới về sự chuy&ecirc;n nghiệp th&ocirc;ng qua qu&acirc;n số h&ugrave;ng hậu, hạ tầng vận tải vượt trội v&agrave; nền tảng c&ocirc;ng nghệ điều phối hiện đại.', 'Giữa bối cảnh thị trường dịch vụ lắp đặt vẫn còn nhiều dư địa phát triển, Thợ Điện máy XANH đang dần thiết lập một ''định nghĩa'' mới về sự chuyên nghiệp thông qua quân số hùng hậu, hạ tầng vận tải vượt trội và nền tảng công nghệ điều phối hiện đại.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/picture2-1775131687964365411971-52-0-927-1400-crop-17751317841951848054408.jpg', NULL, '2026-04-02 12:20:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/tho-dien-may-xanh-khi-su-tan-tam-duoc-khang-dinh-qua-tay-nghe-chuan-hang-185260402191037749.htm", "link": "https://thanhnien.vn/tho-dien-may-xanh-khi-su-tan-tam-duoc-khang-dinh-qua-tay-ngh