INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (142, 4, 'https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm', 'https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm', 'Khu tây TP.HCM: ‘Vùng trũng giá’ trước chu kỳ mới', '<a href="https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/1-1775033408317503760505-0-0-852-1363-crop-17750334313401645974052.jpg"></a> Khi mặt bằng gi&aacute; bất động sản tại nhiều khu vực TP.HCM, đặc biệt l&agrave; khu đ&ocirc;ng, đ&atilde; thiết lập ở ngưỡng cao, khu t&acirc;y đang dần được nh&igrave;n nhận lại như một khu vực c&ograve;n nhiều dư địa. Trong bối cảnh đ&oacute;, c&aacute;c dự &aacute;n quy m&ocirc; lớn, c&oacute; khả năng h&igrave;nh th&agrave;nh nhịp sống v&agrave; giao thương tại chỗ bắt đầu thu h&uacute;t sự quan t&acirc;m của thị trường.', 'Khi mặt bằng giá bất động sản tại nhiều khu vực TP.HCM, đặc biệt là khu đông, đã thiết lập ở ngưỡng cao, khu tây đang dần được nhìn nhận lại như một khu vực còn nhiều dư địa. Trong bối cảnh đó, các dự án quy mô lớn, có khả năng hình thành nhịp sống và giao thương tại chỗ bắt đầu thu hút sự quan tâm của thị trường.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/1-1775033408317503760505-0-0-852-1363-crop-17750334313401645974052.jpg', NULL, '2026-04-02 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm", "link": "https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm", "title": "Khu t&acirc;y TP.HCM: &lsquo;V&ugrave;ng trũng gi&aacute;&rsquo; trước chu kỳ mới", "content": "<a href=\"https://thanhnien.vn/khu-tay-tphcm-vung-trung-gia-truoc-chu-ky-moi-185260401155919336.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/1-1775033408317503760505-0-0-852-1363-crop-17750334313401645974052.jpg\"></a> Khi mặt bằng gi&aacute; bất động sản tại nhiều khu vực TP.HCM, đặc biệt l&agrave; khu đ&ocirc;ng, đ&atilde; thiết lập ở ngưỡng cao, khu t&acirc;y đang dần được nh&igrave;n nhận lại như một khu vực c&ograve;n nhiều dư địa. Trong bối cảnh đ&oacute;, c&aacute;c dự &aacute;n quy m&ocirc; lớn, c&oacute; khả năng h&igrave;nh th&agrave;nh nhịp sống v&agrave; giao thương tại chỗ bắt đầu thu h&uacute;t sự quan t&acirc;m của thị trường.", "isoDate": "2026-04-02T01:00:00.000Z", "pubDate": "Thu, 02 Apr 26 08:00:00 +0700", "contentSnippet": "Khi mặt bằng giá bất động sản tại nhiều khu vực TP.HCM, đặc biệt là khu đông, đã thiết lập ở ngưỡng cao, khu tây đang dần được nhìn nhận lại như một khu vực còn nhiều dư địa. Trong bối cảnh đó, các dự án quy mô lớn, có khả năng hình thành nhịp sống và giao thương tại chỗ bắt đầu thu hút sự quan tâm của thị trường."}', '2026-04-05 15:13:21.912966+00', '2026-04-08 14:21:49.708984+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.708984+00', 7, '0ed1cc9582b016032d421f67d3d78c87429d5812a1b651403699c26fa657172a', '2026-04-07 15:01:37.824291+00', 'ai-ner');
