INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (431, 2, 'https://cafef.vn/petrolimex-trinh-ke-hoach-tra-co-tuc-tien-mat-ty-le-12-doanh-thu-cao-nhat-lich-su-neu-ap-luc-giam-san-luong-do-tac-dong-cua-xe-dien-188260406133954892.chn', 'https://cafef.vn/petrolimex-trinh-ke-hoach-tra-co-tuc-tien-mat-ty-le-12-doanh-thu-cao-nhat-lich-su-neu-ap-luc-giam-san-luong-do-tac-dong-cua-xe-dien-188260406133954892.chn', 'Petrolimex trình kế hoạch trả cổ tức tiền mặt tỷ lệ 12%, doanh thu cao nhất lịch sử, nêu áp lực giảm sản lượng do tác động của xe điện', '<a href="https://cafef.vn/petrolimex-trinh-ke-hoach-tra-co-tuc-tien-mat-ty-le-12-doanh-thu-cao-nhat-lich-su-neu-ap-luc-giam-san-luong-do-tac-dong-cua-xe-dien-188260406133954892.chn"><img src="https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/6/avatar1775457487376-17754574879181156824512.jpg"></a> HĐQT Petrolimex dự kiến trình cổ đông kế hoạch kinh doanh năm 2026 với doanh thu hợp nhất đạt 315.000 tỷ đồng, tăng 2% so với thực hiện năm 2025. Kế hoạch lợi nhuận trước thuế là 3.380 tỷ đồng, giảm 7% so với cùng kỳ.', 'HĐQT Petrolimex dự kiến trình cổ đông kế hoạch kinh doanh năm 2026 với doanh thu hợp nhất đạt 315.000 tỷ đồng, tăng 2% so với thực hiện năm 2025. Kế hoạch lợi nhuận trước thuế là 3.380 tỷ đồng, giảm 7% so với cùng kỳ.', 'https://cafefcdn.com/zoom/600_315/203337114487263232/2026/4/6/avatar1775457487376-17754574879181156824512.jpg', NULL, '2026-04-06 06:39:00+00', 'Doanh nghiệp | cafef', 'https://cafef.vn/doanh-nghiep.chn', '{"guid": "https://cafef.vn/petrolimex-trinh-ke-hoach-tra-co-tuc-tien-mat-ty-le-12-doanh-thu-cao-nhat-lich-su-neu-ap-luc-giam-san-luong-do-tac-dong-cua-xe-dien-188260406133954892.chn", "link": "https://cafef.vn/petrolimex-tr