INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1604, 30, 'https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-bay-dip-gio-to-va-30-4-1-5/416043.html', 'https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-bay-dip-gio-to-va-30-4-1-5/416043.html', 'Vietnam Airlines Group dự kiến khai thác gần 5.500 chuyến bay dịp Giỗ Tổ và 30/4 – 1/5', '<a href="https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-bay-dip-gio-to-va-30-4-1-5/416043.html"><img width="180" height="120" src="https://image.bnews.vn/MediaUpload/Medium/2025/10/26/anh-minh-hoa-1-20250630115007-20251026092045.jpg"/></a>Vietnam Airlines Group dự kiến cung ứng gần 1,12 triệu ghế trên các chuyến bay nội địa và quốc tế dịp cao điểm Giỗ Tổ Hùng Vương và kỳ nghỉ lễ 30/4 – 1/5 năm 2026, tăng 15,5% so với cùng kỳ năm 2025.<br/>', 'Vietnam Airlines Group dự kiến cung ứng gần 1,12 triệu ghế trên các chuyến bay nội địa và quốc tế dịp cao điểm Giỗ Tổ Hùng Vương và kỳ nghỉ lễ 30/4 – 1/5 năm 2026, tăng 15,5% so với cùng kỳ năm 2025.', 'https://image.bnews.vn/MediaUpload/Medium/2025/10/26/anh-minh-hoa-1-20250630115007-20251026092045.jpg', NULL, '2026-04-02 12:03:52+00', 'Chuyển động DN - Bnews.vn RSS', 'https://bnews.vn/rss/chuyen-dong-dn-24.rss', '{"guid": "https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-bay-dip-gio-to-va-30-4-1-5/416043.html", "link": "https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-bay-dip-gio-to-va-30-4-1-5/416043.html", "title": "Vietnam Airlines Group dự kiến khai thác gần 5.500 chuyến bay dịp Giỗ Tổ và 30/4 – 1/5", "content": "<a href=\"https://bnews.vn/vietnam-airlines-group-du-kien-khai-thac-gan-5-500-chuyen-