INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1888, 60, 'https://cafebiz.vn/ly-do-bat-buoc-chuyen-khoan-tu-5-trieu-dong-lan-176260318152827914.chn', 'https://cafebiz.vn/ly-do-bat-buoc-chuyen-khoan-tu-5-trieu-dong-lan-176260318152827914.chn', 'Lý do bắt buộc chuyển khoản từ 5 triệu đồng/lần', '<a href="https://cafebiz.vn/ly-do-bat-buoc-chuyen-khoan-tu-5-trieu-dong-lan-176260318152827914.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/18/avatar1773822454317-177382245552038894398.webp"></a>  Kể từ ngày 15/12/2025, nếu trả lương, tiền công từng lần từ 5 triệu đồng trở lên cho người lao động, doanh nghiệp bắt buộc phải thanh toán không dùng tiền mặt để khoản chi được tính vào chi phí được trừ khi xác định thu nhập chịu thuế thu nhập doanh nghiệp. Nhiều băn khoăn đã được đặt ra về quy định mới.', 'Kể từ ngày 15/12/2025, nếu trả lương, tiền công từng lần từ 5 triệu đồng trở lên cho người lao động, doanh nghiệp bắt buộc phải thanh toán không dùng tiền mặt để khoản chi được tính vào chi phí được trừ khi xác định thu nhập chịu thuế thu nhập doanh nghiệp. Nhiều băn khoăn đã được đặt ra về quy định mới.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/18/avatar1773822454317-177382245552038894398.webp', NULL, '2026-03-18 09:27:00+00', 'Ngân hàng - Tài chính | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/ngan-hang-tai-chinh.chn', '{"guid": "https://cafebiz.vn/ly-do-bat-buoc-chuyen-khoan-tu-5-trieu-dong-lan-176260318152827914.chn", "link": "https://cafebiz.vn/ly-do-bat-buoc-chuyen-khoan-tu-5-trieu-dong-lan-176260318152827914.chn", "title": "Lý do bắt buộc chuyển khoản từ 5 triệu đồng/lần", "content": "<a href=\"https://cafebiz.vn/ly-do-bat-