INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (138, 4, 'https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm', 'https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm', 'Capital Square định hình chuẩn sống đa tầng giữa lõi đô thị Đà Nẵng', '<a href="https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/a-1775119508302792449914-58-0-933-1400-crop-17751195227171011281623.jpg"></a> Vừa qua, tại Cung Hội nghị quốc tế Ariyana Đ&agrave; Nẵng, sự kiện &#039;Mỹ cảnh tầng kh&ocirc;ng&#039; đ&atilde; mang đến những h&igrave;nh dung đầu ti&ecirc;n về sa b&agrave;n dự &aacute;n Capital Square, qua đ&oacute; ph&aacute;c họa trọn vẹn cấu tr&uacute;c đ&ocirc; thị đa tầng với kh&ocirc;ng gian sống, thương mại v&agrave; trải nghiệm ho&agrave;n hảo d&agrave;nh cho giới tinh hoa.', 'Vừa qua, tại Cung Hội nghị quốc tế Ariyana Đà Nẵng, sự kiện ''Mỹ cảnh tầng không'' đã mang đến những hình dung đầu tiên về sa bàn dự án Capital Square, qua đó phác họa trọn vẹn cấu trúc đô thị đa tầng với không gian sống, thương mại và trải nghiệm hoàn hảo dành cho giới tinh hoa.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/a-1775119508302792449914-58-0-933-1400-crop-17751195227171011281623.jpg', NULL, '2026-04-02 08:42:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm", "link": "https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm", "title": "Capital Square định h&igrave;nh chuẩn sống đa tầng giữa l&otilde;i đ&ocirc; thị Đ&agrave; Nẵng", "content": "<a href=\"https://thanhnien.vn/capital-square-dinh-hinh-chuan-song-da-tang-giua-loi-do-thi-da-nang-185260402154641474.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/a-1775119508302792449914-58-0-933-1400-crop-17751195227171011281623.jpg\"></a> Vừa qua, tại Cung Hội nghị quốc tế Ariyana Đ&agrave; Nẵng, sự kiện &#039;Mỹ cảnh tầng kh&ocirc;ng&#039; đ&atilde; mang đến những h&igrave;nh dung đầu ti&ecirc;n về sa b&agrave;n dự &aacute;n Capital Square, qua đ&oacute; ph&aacute;c họa trọn vẹn cấu tr&uacute;c đ&ocirc; thị đa tầng với kh&ocirc;ng gian sống, thương mại v&agrave; trải nghiệm ho&agrave;n hảo d&agrave;nh cho giới tinh hoa.", "isoDate": "2026-04-02T08:42:00.000Z", "pubDate": "Thu, 02 Apr 26 15:42:00 +0700", "contentSnippet": "Vừa qua, tại Cung Hội nghị quốc tế Ariyana Đà Nẵng, sự kiện ''Mỹ cảnh tầng không'' đã mang đến những hình dung đầu tiên về sa bàn dự án Capital Square, qua đó phác họa trọn vẹn cấu trúc đô thị đa tầng với không gian sống, thương mại và trải nghiệm hoàn hảo dành cho giới tinh hoa."}', '2026-04-05 15:13:21.901207+00', '2026-04-08 14:21:49.701205+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.701205+00', 7, '593c90280aa2053af80258128208a845aca5628a717b11aeef1f9ed5921307cb', '2026-04-07 15:01:37.200373+00', 'ai-ner');
