INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (145, 4, 'https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm', 'https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm', 'Vietnam Airlines chuẩn bị điều chỉnh mạng bay, kiểm soát chặt chi phí', '<a href="https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/31/anh-minh-hoa-1-1-17749454666171119872573-0-117-1440-2421-crop-17749455003611923785972.jpg"></a> Tổng c&ocirc;ng ty H&agrave;ng kh&ocirc;ng Việt Nam (Vietnam Airlines) vừa c&ocirc;ng bố b&aacute;o c&aacute;o t&agrave;i ch&iacute;nh hợp nhất sau so&aacute;t x&eacute;t năm 2025, đồng thời cập nhật t&igrave;nh h&igrave;nh hoạt động qu&yacute; 1/2026 v&agrave; định hướng điều h&agrave;nh trong bối cảnh thị trường quốc tế tiếp tục biến động phức tạp do xung đột tại Trung Đ&ocirc;ng.', 'Tổng công ty Hàng không Việt Nam (Vietnam Airlines) vừa công bố báo cáo tài chính hợp nhất sau soát xét năm 2025, đồng thời cập nhật tình hình hoạt động quý 1/2026 và định hướng điều hành trong bối cảnh thị trường quốc tế tiếp tục biến động phức tạp do xung đột tại Trung Đông.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/31/anh-minh-hoa-1-1-17749454666171119872573-0-117-1440-2421-crop-17749455003611923785972.jpg', NULL, '2026-03-31 09:01:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm", "link": "https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm", "title": "Vietnam Airlines chuẩn bị điều chỉnh mạng bay, kiểm so&aacute;t chặt chi ph&iacute;", "content": "<a href=\"https://thanhnien.vn/vietnam-airlines-chuan-bi-dieu-chinh-mang-bay-kiem-soat-chat-chi-phi-185260331152533241.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/31/anh-minh-hoa-1-1-17749454666171119872573-0-117-1440-2421-crop-17749455003611923785972.jpg\"></a> Tổng c&ocirc;ng ty H&agrave;ng kh&ocirc;ng Việt Nam (Vietnam Airlines) vừa c&ocirc;ng bố b&aacute;o c&aacute;o t&agrave;i ch&iacute;nh hợp nhất sau so&aacute;t x&eacute;t năm 2025, đồng thời cập nhật t&igrave;nh h&igrave;nh hoạt động qu&yacute; 1/2026 v&agrave; định hướng điều h&agrave;nh trong bối cảnh thị trường quốc tế tiếp tục biến động phức tạp do xung đột tại Trung Đ&ocirc;ng.", "isoDate": "2026-03-31T09:01:00.000Z", "pubDate": "Tue, 31 Mar 26 16:01:00 +0700", "contentSnippet": "Tổng công ty Hàng không Việt Nam (Vietnam Airlines) vừa công bố báo cáo tài chính hợp nhất sau soát xét năm 2025, đồng thời cập nhật tình hình hoạt động quý 1/2026 và định hướng điều hành trong bối cảnh thị trường quốc tế tiếp tục biến động phức tạp do xung đột tại Trung Đông."}', '2026-04-05 15:13:21.920756+00', '2026-04-08 14:21:49.714867+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.714867+00', 7, '5c737d6da9caba6a458dd779a80d281cb3cacde51fecf3d5a5dbb264d76650e1', '2026-04-07 15:01:38.332837+00', 'ai-ner');
