INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1865, 60, 'https://cafebiz.vn/bidv-vietcombank-vietinbank-va-agribank-du-kien-bom-1-trieu-ty-dong-cho-nen-kinh-te-trong-nam-2026-176260327140024164.chn', 'https://cafebiz.vn/bidv-vietcombank-vietinbank-va-agribank-du-kien-bom-1-trieu-ty-dong-cho-nen-kinh-te-trong-nam-2026-176260327140024164.chn', 'BIDV, Vietcombank, VietinBank và Agribank dự kiến bơm 1 triệu tỷ đồng cho nền kinh tế trong năm 2026', '<a href="https://cafebiz.vn/bidv-vietcombank-vietinbank-va-agribank-du-kien-bom-1-trieu-ty-dong-cho-nen-kinh-te-trong-nam-2026-176260327140024164.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/27/avatar1774594754278-1774594754633495355709.jpg"></a> Theo Tổng Giám đốc BIDV Lê Ngọc Lâm, trong năm 2026, với tốc độ tăng trưởng tín dụng bình quân do Ngân hàng Nhà nước giao khoảng 11 - 12%, các ngân hàng thương mại nhà nước dự kiến gia tăng giải ngân khoảng 1 triệu tỷ đồng, để phục vụ các nhu cầu vốn của nền kinh tế.', 'Theo Tổng Giám đốc BIDV Lê Ngọc Lâm, trong năm 2026, với tốc độ tăng trưởng tín dụng bình quân do Ngân hàng Nhà nước giao khoảng 11 - 12%, các ngân hàng thương mại nhà nước dự kiến gia tăng giải ngân khoảng 1 triệu tỷ đồng, để phục vụ các nhu cầu vốn của nền kinh tế.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/27/avatar1774594754278-1774594754633495355709.jpg', NULL, '2026-03-27 07:39:00+00', 'Ngân hàng - Tài chính | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/ngan-hang-tai-chinh.chn', '{"guid": "https://cafebiz.vn/bidv-vietcombank-vietinbank-va-agribank-du-kien-bom-1-trieu-ty-dong-cho-nen-kinh-te-trong-nam-2026-176260327140024164.chn", "link": "https://cafebiz.vn/bidv