INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1868, 60, 'https://cafebiz.vn/sacombank-trien-khai-mo-hinh-lam-viec-hybrid-huong-ung-chu-truong-tiet-kiem-nang-luong-176260325121253481.chn', 'https://cafebiz.vn/sacombank-trien-khai-mo-hinh-lam-viec-hybrid-huong-ung-chu-truong-tiet-kiem-nang-luong-176260325121253481.chn', 'SACOMBANK triển khai mô hình làm việc Hybrid, hưởng ứng chủ trương tiết kiệm năng lượng', '<a href="https://cafebiz.vn/sacombank-trien-khai-mo-hinh-lam-viec-hybrid-huong-ung-chu-truong-tiet-kiem-nang-luong-176260325121253481.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/25/avatar1774415528274-1774415533762527839827.jpeg"></a> Trong bối cảnh thị trường năng lượng toàn cầu biến động dưới tác động của các yếu tố địa chính trị, nhiều quốc gia, đặc biệt tại Đông Nam Á, đang đẩy mạnh các giải pháp tiết kiệm nhiên liệu và giảm tải hệ thống năng lượng. Xu hướng làm việc linh hoạt, giảm di chuyển và tối ưu tiêu thụ điện đang được xem là một trong những giải pháp hiệu quả.', 'Trong bối cảnh thị trường năng lượng toàn cầu biến động dưới tác động của các yếu tố địa chính trị, nhiều quốc gia, đặc biệt tại Đông Nam Á, đang đẩy mạnh các giải pháp tiết kiệm nhiên liệu và giảm tải hệ thống năng lượng. Xu hướng làm việc linh hoạt, giảm di chuyển và tối ưu tiêu thụ điện đang được xem là một trong những giải pháp hiệu quả.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/25/avatar1774415528274-1774415533762527839827.jpeg', NULL, '2026-03-25 05:12:00+00', 'Ngân hàng - Tài chính | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/ngan-hang-tai-chinh.chn', '{"guid": "https://cafebiz.vn/sacombank-trien-khai-mo-hinh-lam-viec-hybrid-huong-