INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (492, 4, 'https://thanhnien.vn/hoi-nghi-khuc-xa-nhan-khoa-mat-sai-gon-2026-kiem-soat-can-thi-tren-lam-sang-185260406135855523.htm', 'https://thanhnien.vn/hoi-nghi-khuc-xa-nhan-khoa-mat-sai-gon-2026-kiem-soat-can-thi-tren-lam-sang-185260406135855523.htm', 'Hội nghị Khúc xạ nhãn khoa Mắt Sài Gòn 2026: Kiểm soát cận thị trên lâm sàng', '<a href="https://thanhnien.vn/hoi-nghi-khuc-xa-nhan-khoa-mat-sai-gon-2026-kiem-soat-can-thi-tren-lam-sang-185260406135855523.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/6/anh-bia-17754615083161622972860-86-0-1366-2048-crop-1775461600080739357090.png"></a> Trong bối cảnh cận thị học đường ng&agrave;y c&agrave;ng gia tăng v&agrave; c&oacute; xu hướng tiến triển sớm, việc kiểm so&aacute;t cận thị kh&ocirc;ng chỉ dừng lại ở điều chỉnh thị lực m&agrave; đ&ograve;i hỏi c&aacute;c giải ph&aacute;p dựa tr&ecirc;n bằng chứng khoa học v&agrave; theo d&otilde;i l&acirc;u d&agrave;i. ', 'Trong bối cảnh cận thị học đường ngày càng gia tăng và có xu hướng tiến triển sớm, việc kiểm soát cận thị không chỉ dừng lại ở điều chỉnh thị lực mà đòi hỏi các giải pháp dựa trên bằng chứng khoa học và theo dõi lâu dài.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/6/anh-bia-17754615083161622972860-86-0-1366-2048-crop-1775461600080739357090.png', NULL, '2026-04-06 06:46:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/hoi-nghi-khuc-xa-nhan-khoa-mat-sai-gon-2026-kiem-soat-can-thi-tren-lam-sang-185260406135855523.htm", "link": "https://thanhnien.vn/hoi-nghi-khuc-xa-nhan-khoa-mat-sai-gon-2026-kiem-soat-can-thi-tren-