INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (4602, 59, 'https://cafebiz.vn/chu-toa-nha-the-grand-hanoi-so-22-24-hang-bai-bao-lai-dot-bien-15000-ty-dong-nam-2025-tong-tai-san-tang-vot-len-gan-150000-ty-176260408065150846.chn', 'https://cafebiz.vn/chu-toa-nha-the-grand-hanoi-so-22-24-hang-bai-bao-lai-dot-bien-15000-ty-dong-nam-2025-tong-tai-san-tang-vot-len-gan-150000-ty-176260408065150846.chn', 'Chủ toà nhà The Grand Hanoi số 22-24 Hàng Bài báo lãi đột biến 15.000 tỷ đồng năm 2025, tổng tài sản tăng vọt lên gần 150.000 tỷ', '<a href="https://cafebiz.vn/chu-toa-nha-the-grand-hanoi-so-22-24-hang-bai-bao-lai-dot-bien-15000-ty-dong-nam-2025-tong-tai-san-tang-vot-len-gan-150000-ty-176260408065150846.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/8/avatar1775624664961-17756246675631954686543.jpg"></a> Tính đến cuối năm 2025, tổng tài sản của công ty đạt 146.183 tỷ đồng, tăng gấp 10 lần so với đầu năm và vượt xa quy mô của nhiều doanh nghiệp bất động sản niêm yết.', 'Tính đến cuối năm 2025, tổng tài sản của công ty đạt 146.183 tỷ đồng, tăng gấp 10 lần so với đầu năm và vượt xa quy mô của nhiều doanh nghiệp bất động sản niêm yết.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/4/8/avatar1775624664961-17756246675631954686543.jpg', NULL, '2026-04-08 01:32:00+00', 'Kinh doanh | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh.chn', '{"guid": "https://cafebiz.vn/chu-toa-nha-the-grand-hanoi-so-22-24-hang-bai-bao-lai-dot-bien-15000-ty-dong-nam-2025-tong-tai-san-tang-vot-len-gan-150000-ty-176260408065150846.chn", "link": "https://cafebiz.vn/chu-toa-nha-the-grand-hanoi-so-22-24-hang-bai-bao-lai-dot-bien-15000-ty-dong-nam-2025-tong-tai-san-tang-v