INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1873, 60, 'https://cafebiz.vn/ngan-hang-nha-nuoc-tang-luong-omo-chao-thau-nhung-van-hut-ve-gan-26000-ty-lai-suat-lien-ngan-hang-tiep-tuc-tang-176260324095512112.chn', 'https://cafebiz.vn/ngan-hang-nha-nuoc-tang-luong-omo-chao-thau-nhung-van-hut-ve-gan-26000-ty-lai-suat-lien-ngan-hang-tiep-tuc-tang-176260324095512112.chn', 'Ngân hàng Nhà nước tăng lượng OMO chào thầu nhưng vẫn hút về gần 26.000 tỷ, lãi suất liên ngân hàng tiếp tục tăng', '<a href="https://cafebiz.vn/ngan-hang-nha-nuoc-tang-luong-omo-chao-thau-nhung-van-hut-ve-gan-26000-ty-lai-suat-lien-ngan-hang-tiep-tuc-tang-176260324095512112.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/24/avatar1774320821284-17743208231631636781670.jpg"></a> Ngân hàng Nhà nước tiếp tục hút ròng gần 26.000 tỷ đồng thanh khoản trong phiên 23/3 dù tăng mạnh quy mô chào thầu OMO, kéo khối lượng lưu hành trên kênh cầm cố xuống mức thấp nhất gần 5 tháng. Trong bối cảnh đó, lãi suất liên ngân hàng VND đồng loạt tăng trở lại ở các kỳ hạn chủ chốt.', 'Ngân hàng Nhà nước tiếp tục hút ròng gần 26.000 tỷ đồng thanh khoản trong phiên 23/3 dù tăng mạnh quy mô chào thầu OMO, kéo khối lượng lưu hành trên kênh cầm cố xuống mức thấp nhất gần 5 tháng. Trong bối cảnh đó, lãi suất liên ngân hàng VND đồng loạt tăng trở lại ở các kỳ hạn chủ chốt.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/24/avatar1774320821284-17743208231631636781670.jpg', NULL, '2026-03-24 03:37:00+00', 'Ngân hàng - Tài chính | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/ngan-hang-tai-chinh.chn', '{"guid": "https://cafebiz.vn/ngan-hang-nha-nuoc-tang-luong-omo-chao-thau-nhung-van-hut-ve-gan