INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (1878, 60, 'https://cafebiz.vn/lai-suat-ngan-hang-techcombank-thang-3-2026-tang-manh-gui-online-cao-hon-nhieu-tai-quay-176260322200207559.chn', 'https://cafebiz.vn/lai-suat-ngan-hang-techcombank-thang-3-2026-tang-manh-gui-online-cao-hon-nhieu-tai-quay-176260322200207559.chn', 'Lãi suất ngân hàng Techcombank tháng 3/2026: Tăng mạnh, gửi online cao hơn nhiều tại quầy', '<a href="https://cafebiz.vn/lai-suat-ngan-hang-techcombank-thang-3-2026-tang-manh-gui-online-cao-hon-nhieu-tai-quay-176260322200207559.chn"><img src="https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/22/avatar1774184471795-17741844742581325660925.jpg"></a> Trong tháng 3/2026, Ngân hàng TMCP Kỹ Thương Việt Nam (Techcombank) tiếp tục duy trì mặt bằng lãi suất huy động theo hướng ưu tiên kênh số. Theo biểu lãi suất mới nhất, tiền gửi online vẫn có mức lãi suất cao hơn rõ rệt so với gửi tiền tại quầy ở hầu hết các kỳ hạn, đặc biệt là nhóm kỳ hạn dài.', 'Trong tháng 3/2026, Ngân hàng TMCP Kỹ Thương Việt Nam (Techcombank) tiếp tục duy trì mặt bằng lãi suất huy động theo hướng ưu tiên kênh số. Theo biểu lãi suất mới nhất, tiền gửi online vẫn có mức lãi suất cao hơn rõ rệt so với gửi tiền tại quầy ở hầu hết các kỳ hạn, đặc biệt là nhóm kỳ hạn dài.', 'https://cafebiz.cafebizcdn.vn/zoom/700_438/162123310254002176/2026/3/22/avatar1774184471795-17741844742581325660925.jpg', NULL, '2026-03-22 14:24:00+00', 'Ngân hàng - Tài chính | Cafebiz.vn', 'https://cafebiz.vn/cau-chuyen-kinh-doanh/ngan-hang-tai-chinh.chn', '{"guid": "https://cafebiz.vn/lai-suat-ngan-hang-techcombank-thang-3-2026-tang-manh-gui-online-cao-hon-nhieu-tai-quay-176260322200207559.chn", "link": "https://cafebiz.vn/l