INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (4763, 4, 'https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm', 'https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm', 'Chiết khấu bán lẻ dầu diesel vọt lên 13.000 đồng/lít?', '<a href="https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/8/gia-xang-dau-hom-nay-r-1768354208071369248893-0-0-450-720-crop-17756175651652054833914.jpg"></a> Gi&aacute; dầu thế giới biến động khiến thị trường xăng dầu trong nước c&oacute; những thay đổi nhiều về mức chiết khấu b&aacute;n lẻ xăng dầu. Đặc biệt, chiết khấu b&aacute;n lẻ d&agrave;nh cho dầu diesel tăng vọt.', 'Giá dầu thế giới biến động khiến thị trường xăng dầu trong nước có những thay đổi nhiều về mức chiết khấu bán lẻ xăng dầu. Đặc biệt, chiết khấu bán lẻ dành cho dầu diesel tăng vọt.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/8/gia-xang-dau-hom-nay-r-1768354208071369248893-0-0-450-720-crop-17756175651652054833914.jpg', NULL, '2026-04-08 03:50:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm", "link": "https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm", "title": "Chiết khấu b&aacute;n lẻ dầu diesel vọt l&ecirc;n 13.000 đồng/l&iacute;t?", "content": "<a href=\"https://thanhnien.vn/chiet-khau-ban-le-dau-diesel-vot-len-13000-dong-lit-185260408101033609.htm\"><img src=\"https://images2