INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (4764, 4, 'https://thanhnien.vn/fwd-tai-tro-1-ti-tai-thiet-moi-truong-hoc-tap-cho-hoc-sinh-tinh-khanh-hoa-185260408155215402.htm', 'https://thanhnien.vn/fwd-tai-tro-1-ti-tai-thiet-moi-truong-hoc-tap-cho-hoc-sinh-tinh-khanh-hoa-185260408155215402.htm', 'FWD tài trợ 1 tỉ tái thiết môi trường học tập cho học sinh tỉnh Khánh Hòa', '<a href="https://thanhnien.vn/fwd-tai-tro-1-ti-tai-thiet-moi-truong-hoc-tap-cho-hoc-sinh-tinh-khanh-hoa-185260408155215402.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/8/dsc07549-1775638181903123487305-0-6-1177-1889-crop-1775638272332112319463.jpg"></a> Tập đo&agrave;n FWD, th&ocirc;ng qua Quỹ Từ thiện B&ocirc;ng Hồng Nhỏ (Little Roses Foundation), đ&atilde; trao tặng 76 bộ m&aacute;y t&iacute;nh cho ba cơ sở gi&aacute;o dục tại tỉnh Kh&aacute;nh H&ograve;a, khu vực chịu nhiều ảnh hưởng nặng nề bởi b&atilde;o lũ v&agrave;o cuối năm 2025 với mong muốn g&oacute;p phần san sẻ kh&oacute; khăn v&agrave; tiếp th&ecirc;m động lực để c&aacute;c em học sinh vững bước tr&ecirc;n h&agrave;nh tr&igrave;nh học tập.', 'Tập đoàn FWD, thông qua Quỹ Từ thiện Bông Hồng Nhỏ (Little Roses Foundation), đã trao tặng 76 bộ máy tính cho ba cơ sở giáo dục tại tỉnh Khánh Hòa, khu vực chịu nhiều ảnh hưởng nặng nề bởi bão lũ vào cuối năm 2025 với mong muốn góp phần san sẻ khó khăn và tiếp thêm động lực để các em học sinh vững bước trên hành trình học tập.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/8/dsc07549-1775638181903123487305-0-6-1177-1889-crop-1775638272332112319463.jpg', NULL, '2026-04-08 09:01:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm'