INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (4768, 4, 'https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm', 'https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm', 'GENERALI VIỆT NAM - 15 NĂM HÀNH TRÌNH BẢO VỆ TỪNG KHOẢNH KHẮC', '<a href="https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/3/thumbnail-1775184787256344931253-0-22-1186-1920-crop-1775184802668271372815.jpg"></a> Xuy&ecirc;n suốt 15 năm s&aacute;t c&aacute;nh c&ugrave;ng thị trường Việt Nam, Generali kh&ocirc;ng ngừng khẳng định dấu ấn của một doanh nghiệp bảo hiểm nh&acirc;n thọ theo đuổi ph&aacute;t triển bền vững, đặt kh&aacute;ch h&agrave;ng l&agrave;m trọng t&acirc;m v&agrave; ki&ecirc;n định với sứ mệnh trở th&agrave;nh &quot;Người bạn Trọn đời&quot; của h&agrave;ng triệu gia đ&igrave;nh Việt.', 'Xuyên suốt 15 năm sát cánh cùng thị trường Việt Nam, Generali không ngừng khẳng định dấu ấn của một doanh nghiệp bảo hiểm nhân thọ theo đuổi phát triển bền vững, đặt khách hàng làm trọng tâm và kiên định với sứ mệnh trở thành "Người bạn Trọn đời" của hàng triệu gia đình Việt.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/3/thumbnail-1775184787256344931253-0-22-1186-1920-crop-1775184802668271372815.jpg', NULL, '2026-04-08 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm", "link": "https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm", "title": "GENERALI VIỆT NAM - 15 NĂM H&Agrave;NH TR&Igrave;NH BẢO VỆ TỪNG KHOẢNH KHẮC", "content": "<a href=\"https://thanhnien.vn/generali-viet-nam-15-nam-hanh-trinh-bao-ve-tung-khoanh-khac-185260403095533544.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/3/thumbnail-1775184787256344931253-0-22-1186-1920-crop-1775184802668271372815.jpg\"></a> Xuy&ecirc;n suốt 15 năm s&aacute;t c&aacute;nh c&ugrave;ng thị trường Việt Nam, Generali kh&ocirc;ng ngừng khẳng định dấu ấn của một doanh nghiệp bảo hiểm nh&acirc;n thọ theo đuổi ph&aacute;t triển bền vững, đặt kh&aacute;ch h&agrave;ng l&agrave;m trọng t&acirc;m v&agrave; ki&ecirc;n định với sứ mệnh trở th&agrave;nh &quot;Người bạn Trọn đời&quot; của h&agrave;ng triệu gia đ&igrave;nh Việt.", "isoDate": "2026-04-08T01:00:00.000Z", "pubDate": "Wed, 08 Apr 26 08:00:00 +0700", "contentSnippet": "Xuyên suốt 15 năm sát cánh cùng thị trường Việt Nam, Generali không ngừng khẳng định dấu ấn của một doanh nghiệp bảo hiểm nhân thọ theo đuổi phát triển bền vững, đặt khách hàng làm trọng tâm và kiên định với sứ mệnh trở thành \"Người bạn Trọn đời\" của hàng triệu gia đình Việt."}', '2026-04-08 14:21:49.665927+00', '2026-04-08 14:21:49.670742+00', '2026-04-08 14:21:49.665927+00', '2026-04-08 14:21:49.665927+00', 1, 'ab7308f2eec5b2d709cc23bd042f813ea0d8ca0d5ce25bbafaf4aa7bae63755a', '2026-04-08 14:21:49.670742+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (133, 4, 'https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm', 'https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm', 'TTC Phú Quốc Kick-off Selavia - Công bố định vị ‘Thành phố Bản Sắc Việt’', '<a href="https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/bnh07583-1775132574829560732783-0-0-875-1400-crop-1775132795451844394408.jpg"></a> Ng&agrave;y 2.4.2026, CTCP To&agrave;n Hải V&acirc;n (TTC Ph&uacute; Quốc) đ&atilde; tổ chức th&agrave;nh c&ocirc;ng sự kiện Kick-off (ra qu&acirc;n) dự &aacute;n Selavia, thu h&uacute;t hơn 500 kh&aacute;ch mời l&agrave; c&aacute;c đối t&aacute;c chiến lược, đơn vị ph&acirc;n phối, đại diện c&aacute;c ng&acirc;n h&agrave;ng, hiệp hội v&agrave; cộng đồng kinh doanh bất động sản tr&ecirc;n to&agrave;n quốc.', 'Ngày 2.4.2026, CTCP Toàn Hải Vân (TTC Phú Quốc) đã tổ chức thành công sự kiện Kick-off (ra quân) dự án Selavia, thu hút hơn 500 khách mời là các đối tác chiến lược, đơn vị phân phối, đại diện các ngân hàng, hiệp hội và cộng đồng kinh doanh bất động sản trên toàn quốc.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/bnh07583-1775132574829560732783-0-0-875-1400-crop-1775132795451844394408.jpg', NULL, '2026-04-03 01:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm", "link": "https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm", "title": "TTC Ph&uacute; Quốc Kick-off Selavia - C&ocirc;ng bố định vị &lsquo;Th&agrave;nh phố Bản Sắc Việt&rsquo;", "content": "<a href=\"https://thanhnien.vn/ttc-phu-quoc-kick-off-selavia-cong-bo-dinh-vi-thanh-pho-ban-sac-viet-185260402192444218.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/2/bnh07583-1775132574829560732783-0-0-875-1400-crop-1775132795451844394408.jpg\"></a> Ng&agrave;y 2.4.2026, CTCP To&agrave;n Hải V&acirc;n (TTC Ph&uacute; Quốc) đ&atilde; tổ chức th&agrave;nh c&ocirc;ng sự kiện Kick-off (ra qu&acirc;n) dự &aacute;n Selavia, thu h&uacute;t hơn 500 kh&aacute;ch mời l&agrave; c&aacute;c đối t&aacute;c chiến lược, đơn vị ph&acirc;n phối, đại diện c&aacute;c ng&acirc;n h&agrave;ng, hiệp hội v&agrave; cộng đồng kinh doanh bất động sản tr&ecirc;n to&agrave;n quốc.", "isoDate": "2026-04-03T01:00:00.000Z", "pubDate": "Fri, 03 Apr 26 08:00:00 +0700", "contentSnippet": "Ngày 2.4.2026, CTCP Toàn Hải Vân (TTC Phú Quốc) đã tổ chức thành công sự kiện Kick-off (ra quân) dự án Selavia, thu hút hơn 500 khách mời là các đối tác chiến lược, đơn vị phân phối, đại diện các ngân hàng, hiệp hội và cộng đồng kinh doanh bất động sản trên toàn quốc."}', '2026-04-05 15:13:21.884588+00', '2026-04-08 14:21:49.688485+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.688485+00', 7, '31699ad9ac5a38236977c3ae41bce166f2d35b4854d5e375297b6cc78dbab38b', '2026-04-07 15:01:36.011003+00', 'rule');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (143, 4, 'https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm', 'https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm', 'Vừa có người trúng 23 giải Vietlott, ''hốt'' hơn 10 tỉ đồng', '<a href="https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/picture1-17750370920001904581600-0-0-817-1307-crop-1775037130625559991643.jpg"></a> Một người chơi Vietlott tại Hưng Y&ecirc;n vừa tr&uacute;ng c&ugrave;ng l&uacute;c 23 giải của sản phẩm xổ số tự chọn Max 3D Pro, với tổng gi&aacute; trị hơn 10 tỉ đồng.', 'Một người chơi Vietlott tại Hưng Yên vừa trúng cùng lúc 23 giải của sản phẩm xổ số tự chọn Max 3D Pro, với tổng giá trị hơn 10 tỉ đồng.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/picture1-17750370920001904581600-0-0-817-1307-crop-1775037130625559991643.jpg', NULL, '2026-04-01 10:24:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm", "link": "https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm", "title": "Vừa c&oacute; người tr&uacute;ng 23 giải Vietlott, &#039;hốt&#039; hơn 10 tỉ đồng", "content": "<a href=\"https://thanhnien.vn/vua-co-nguoi-trung-23-giai-vietlott-hot-hon-10-ti-dong-185260401165327183.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/4/1/picture1-1775037092000190458160