INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (149, 4, 'https://thanhnien.vn/tap-doan-brg-trong-gan-11-trieu-cay-xanh-khang-dinh-trach-nhiem-voi-cong-dong-185260330161650924.htm', 'https://thanhnien.vn/tap-doan-brg-trong-gan-11-trieu-cay-xanh-khang-dinh-trach-nhiem-voi-cong-dong-185260330161650924.htm', 'Tập đoàn BRG trồng gần 1,1 triệu cây xanh - Khẳng định trách nhiệm với cộng đồng', '<a href="https://thanhnien.vn/tap-doan-brg-trong-gan-11-trieu-cay-xanh-khang-dinh-trach-nhiem-voi-cong-dong-185260330161650924.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/30/b-17748620860461100511485-198-0-1073-1400-crop-17748621197921302445218.jpg"></a> Với gần 1,1 triệu c&acirc;y xanh được trồng tr&ecirc;n khắp cả nước, Tập đo&agrave;n BRG kh&ocirc;ng chỉ mở rộng diện t&iacute;ch phủ xanh m&agrave; c&ograve;n kiến tạo một m&ocirc; h&igrave;nh ph&aacute;t triển bền vững gắn với tr&aacute;ch nhiệm với cộng đồng. ', 'Với gần 1,1 triệu cây xanh được trồng trên khắp cả nước, Tập đoàn BRG không chỉ mở rộng diện tích phủ xanh mà còn kiến tạo một mô hình phát triển bền vững gắn với trách nhiệm với cộng đồng.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/30/b-17748620860461100511485-198-0-1073-1400-crop-17748621197921302445218.jpg', NULL, '2026-03-30 09:12:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/tap-doan-brg-trong-gan-11-trieu-cay-xanh-khang-dinh-trach-nhiem-voi-cong-dong-185260330161650924.htm", "link": "https://thanhnien.vn/tap-doan-brg-trong-gan-11-trieu-cay-xanh-khang-dinh-trach-nhiem-voi-cong-dong-185260330161650924.htm", "title": "Tập đo&agrave;n BRG trồng gần 1,1 triệu