INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (153, 4, 'https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm', 'https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm', 'Ông Nguyễn Thanh Hải giữ chức Chủ tịch Hội Doanh nhân trẻ Khánh Hòa', '<a href="https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/28/z766557712426961e6c6ee08bf94e53abe31100c37093c-17746590590291421677503-106-0-1706-2560-crop-17746592226701937788551.jpg"></a> Hội Doanh nh&acirc;n trẻ Kh&aacute;nh H&ograve;a đ&atilde; bầu Ban Chấp h&agrave;nh nhiệm kỳ 2026 - 2031 gồm 61 th&agrave;nh vi&ecirc;n. &Ocirc;ng Nguyễn Thanh Hải, Tổng gi&aacute;m đốc C&ocirc;ng ty TNHH Nh&agrave; nước Một th&agrave;nh vi&ecirc;n Yến s&agrave;o Kh&aacute;nh H&ograve;a, được t&iacute;n nhiệm bầu giữ chức Chủ tịch hội.', 'Hội Doanh nhân trẻ Khánh Hòa đã bầu Ban Chấp hành nhiệm kỳ 2026 - 2031 gồm 61 thành viên. Ông Nguyễn Thanh Hải, Tổng giám đốc Công ty TNHH Nhà nước Một thành viên Yến sào Khánh Hòa, được tín nhiệm bầu giữ chức Chủ tịch hội.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/28/z766557712426961e6c6ee08bf94e53abe31100c37093c-17746590590291421677503-106-0-1706-2560-crop-17746592226701937788551.jpg', NULL, '2026-03-28 01:30:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm", "link": "https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm", "title": "&Ocirc;ng Nguyễn Thanh Hải giữ chức Chủ tịch Hội Doanh nh&acirc;n trẻ Kh&aacute;nh H&ograve;a", "content": "<a href=\"https://thanhnien.vn/ong-nguyen-thanh-hai-giu-chuc-chu-tich-hoi-doanh-nhan-tre-khanh-hoa-185260328075331152.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/28/z766557712426961e6c6ee08bf94e53abe31100c37093c-17746590590291421677503-106-0-1706-2560-crop-17746592226701937788551.jpg\"></a> Hội Doanh nh&acirc;n trẻ Kh&aacute;nh H&ograve;a đ&atilde; bầu Ban Chấp h&agrave;nh nhiệm kỳ 2026 - 2031 gồm 61 th&agrave;nh vi&ecirc;n. &Ocirc;ng Nguyễn Thanh Hải, Tổng gi&aacute;m đốc C&ocirc;ng ty TNHH Nh&agrave; nước Một th&agrave;nh vi&ecirc;n Yến s&agrave;o Kh&aacute;nh H&ograve;a, được t&iacute;n nhiệm bầu giữ chức Chủ tịch hội.", "isoDate": "2026-03-28T01:30:00.000Z", "pubDate": "Sat, 28 Mar 26 08:30:00 +0700", "contentSnippet": "Hội Doanh nhân trẻ Khánh Hòa đã bầu Ban Chấp hành nhiệm kỳ 2026 - 2031 gồm 61 thành viên. Ông Nguyễn Thanh Hải, Tổng giám đốc Công ty TNHH Nhà nước Một thành viên Yến sào Khánh Hòa, được tín nhiệm bầu giữ chức Chủ tịch hội."}', '2026-04-05 15:13:21.943978+00', '2026-04-08 14:21:49.731358+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.731358+00', 7, 'f599f5f8a8765dfbb270196af273d0bd8057ec2669e4de83b52e69c1ebcd5f31', '2026-04-07 15:01:40.583698+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (148, 4, 'https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm', 'https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm', 'Nhựa Tiền Phong đồng hành Hội thảo quốc tế ‘TOD với phát triển đường sắt đô thị’', '<a href="https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/30/1-17748729396521905620059-0-0-863-1381-crop-1774872945916426166711.jpg"></a> Ng&agrave;y 26 - 27.3.2026, tại Trường đại học Kiến tr&uacute;c TP.HCM, chuỗi hoạt động triển l&atilde;m v&agrave; hội thảo quốc tế với chủ đề &#039;TOD với ph&aacute;t triển đường sắt đ&ocirc; thị&#039; đ&atilde; diễn ra, quy tụ đ&ocirc;ng đảo đại diện cơ quan quản l&yacute;, chuy&ecirc;n gia, doanh nghiệp v&agrave; tổ chức trong lĩnh vực quy hoạch - x&acirc;y dựng - hạ tầng. ', 'Ngày 26 - 27.3.2026, tại Trường đại học Kiến trúc TP.HCM, chuỗi hoạt động triển lãm và hội thảo quốc tế với chủ đề ''TOD với phát triển đường sắt đô thị'' đã diễn ra, quy tụ đông đảo đại diện cơ quan quản lý, chuyên gia, doanh nghiệp và tổ chức trong lĩnh vực quy hoạch - xây dựng - hạ tầng.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/30/1-17748729396521905620059-0-0-863-1381-crop-1774872945916426166711.jpg', NULL, '2026-03-30 13:00:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm", "link": "https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm", "title": "Nhựa Tiền Phong đồng h&agrave;nh Hội thảo quốc tế &lsquo;TOD với ph&aacute;t triển đường sắt đ&ocirc; thị&rsquo;", "content": "<a href=\"https://thanhnien.vn/nhua-tien-phong-dong-hanh-hoi-thao-quoc-te-tod-voi-phat-trien-duong-sat-do-thi-185260330192325909.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/30/1-17748729396521905620059-0-0-863-1381-crop-1774872945916426166711.jpg\"></a> Ng&agrave;y 26 - 27.3.2026, tại Trường đại học Kiến tr&uacute;c TP.HCM, chuỗi hoạt động triển l&atilde;m v&agrave; hội thảo quốc tế với chủ đề &#039;TOD với ph&aacute;t triển đường sắt đ&ocirc; thị&#039; đ&atilde; diễn ra, quy tụ đ&ocirc;ng đảo đại diện cơ quan quản l&yacute;, chuy&ecirc;n gia, doanh nghiệp v&agrave; tổ chức trong lĩnh vực quy hoạch - x&acirc;y dựng - hạ tầng. ", "isoDate": "2026-03-30T13:00:00.000Z", "pubDate": "Mon, 30 Mar 26 20:00:00 +0700", "contentSnippet": "Ngày 26 - 27.3.2026, tại Trường đại học Kiến trúc TP.HCM, chuỗi hoạt động triển lãm và hội thảo quốc tế với chủ đề ''TOD với phát triển đường sắt đô thị'' đã diễn ra, quy tụ đông đảo đại diện cơ quan quản lý, chuyên gia, doanh nghiệp và tổ chức trong lĩnh vực quy hoạch - xây dựng - hạ tầng."}', '2026-04-05 15:13:21.929511+00', '2026-04-08 14:21:49.720989+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.720989+00', 7, '26cfd2b2cc8dd34c44e4c9afe6d4a6afe658cfb80afe1b2fcc76454dfda58e6b', '2026-04-07 15:01:39.108272+00', 'ai-ner');
INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (154, 4, 'https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai-moi-khoi-dau-ky-nguyen-moi-185260327145836835.htm', 'https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai-moi-khoi-dau-ky-nguyen-moi-185260327145836835.htm', 'DOTHANH AUTO ra mắt xe tải mới, khởi đầu kỷ nguyên mới', '<a href="https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai-moi-khoi-dau-ky-nguyen-moi-185260327145836835.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/1-1774597850754844384378-0-0-1232-1971-crop-17745982225531614515792.png"></a> Tuy&ecirc;n ng&ocirc;n bước v&agrave;o &#039;Kỷ nguy&ecirc;n mới, vươn tầm cao mới&#039; sau gần 35 năm ph&aacute;t triển, DOTHANH AUTO c&ocirc;ng bố ra mắt DOTHANH JP120SL &amp; JP120EXL - hai mẫu xe tải chiến lược mới, hợp t&aacute;c với nh&agrave; sản xuất &ocirc; t&ocirc; to&agrave;n cầu JMC.', 'Tuyên ngôn bước vào ''Kỷ nguyên mới, vươn tầm cao mới'' sau gần 35 năm phát triển, DOTHANH AUTO công bố ra mắt DOTHANH JP120SL & JP120EXL - hai mẫu xe tải chiến lược mới, hợp tác với nhà sản xuất ô tô toàn cầu JMC.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/1-1774597850754844384378-0-0-1232-1971-crop-17745982225531614515792.png', NULL, '2026-03-27 08:30:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai-moi-khoi-dau-ky-nguyen-moi-185260327145836835.htm", "link": "https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai-moi-khoi-dau-ky-nguyen-moi-185260327145836835.htm", "title": "DOTHANH AUTO ra mắt xe tải mới, khởi đầu kỷ nguy&ecirc;n mới", "content": "<a href=\"https://thanhnien.vn/dothanh-auto-ra-mat-xe-tai