INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (156, 4, 'https://thanhnien.vn/nha-may-che-bien-thuc-pham-cp-cu-chi-tang-san-luong-10-lan-sau-10-nam-185260327142601035.htm', 'https://thanhnien.vn/nha-may-che-bien-thuc-pham-cp-cu-chi-tang-san-luong-10-lan-sau-10-nam-185260327142601035.htm', 'Nhà máy chế biến thực phẩm C.P. Củ Chi tăng sản lượng 10 lần sau 10 năm', '<a href="https://thanhnien.vn/nha-may-che-bien-thuc-pham-cp-cu-chi-tang-san-luong-10-lan-sau-10-nam-185260327142601035.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/tham-quan-cp-177459600724758003877-107-0-1707-2560-crop-17745962253861166871036.jpg"></a> Sau 10 năm đi v&agrave;o hoạt động tại Khu c&ocirc;ng nghiệp T&acirc;n Ph&uacute; Trung, x&atilde; Củ Chi (TP. HCM), nh&agrave; m&aacute;y C.P. Củ Chi của C&ocirc;ng ty Chăn nu&ocirc;i C.P. Việt Nam dự kiến đạt c&ocirc;ng suất 33.000 tấn trong năm nay, tăng gần 10 lần so với năm 2016. ', 'Sau 10 năm đi vào hoạt động tại Khu công nghiệp Tân Phú Trung, xã Củ Chi (TP. HCM), nhà máy C.P. Củ Chi của Công ty Chăn nuôi C.P. Việt Nam dự kiến đạt công suất 33.000 tấn trong năm nay, tăng gần 10 lần so với năm 2016.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/27/tham-quan-cp-177459600724758003877-107-0-1707-2560-crop-17745962253861166871036.jpg', NULL, '2026-03-27 07:29:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/nha-may-che-bien-thuc-pham-cp-cu-chi-tang-san-luong-10-lan-sau-10-nam-185260327142601035.htm", "link": "https://thanhnien.vn/nha-may-che-bien-thuc-pham-cp-cu-chi-tang-san-luong-10-lan-sau-10-nam-185260327142601035.htm", "title": "Nh&agrave; m&aac