INSERT INTO public.articles (id, source_id, guid, article_url, title, description_html, description_text, image_url, author_name, published_at, feed_title, feed_link, raw_payload, created_at, updated_at, first_seen_at, last_seen_at, crawl_count, entity_extracted_hash, entity_extracted_at, entity_extraction_source) VALUES (167, 4, 'https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm', 'https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm', 'Xu hướng đặt xe hộ người thân tăng 40%', '<a href="https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm"><img src="https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/24/geminigeneratedimage5t5q5v5t5q5v5t5q-17743164272631484019494-0-143-1396-2377-crop-177431646116383149436.png"></a> Theo dữ liệu từ Be Group c&ocirc;ng bố ng&agrave;y 23.3, chỉ trong v&ograve;ng một năm, tỷ lệ người d&ugrave;ng sử dụng t&iacute;nh năng &quot;đặt hộ&quot; cho người th&acirc;n đ&atilde; tăng từ 15% đầu năm 2025 l&ecirc;n 40% v&agrave;o cuối năm 2025, giai đoạn nền tảng bắt đầu thử nghiệm v&agrave; triển khai t&iacute;nh năng beFamily.', 'Theo dữ liệu từ Be Group công bố ngày 23.3, chỉ trong vòng một năm, tỷ lệ người dùng sử dụng tính năng "đặt hộ" cho người thân đã tăng từ 15% đầu năm 2025 lên 40% vào cuối năm 2025, giai đoạn nền tảng bắt đầu thử nghiệm và triển khai tính năng beFamily.', 'https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/24/geminigeneratedimage5t5q5v5t5q5v5t5q-17743164272631484019494-0-143-1396-2377-crop-177431646116383149436.png', NULL, '2026-03-24 02:08:00+00', 'Doanh nghiệp | Báo Thanh Niên', 'https://thanhnien.vn/kinh-te/doanh-nghiep.htm', '{"guid": "https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm", "link": "https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm", "title": "Xu hướng đặt xe hộ người th&acirc;n tăng 40%", "content": "<a href=\"https://thanhnien.vn/xu-huong-dat-xe-ho-nguoi-than-tang-40-185260324084535242.htm\"><img src=\"https://images2.thanhnien.vn/zoom/600_315/528068263637045248/2026/3/24/geminigeneratedimage5t5q5v5t5q5v5t5q-17743164272631484019494-0-143-1396-2377-crop-177431646116383149436.png\"></a> Theo dữ liệu từ Be Group c&ocirc;ng bố ng&agrave;y 23.3, chỉ trong v&ograve;ng một năm, tỷ lệ người d&ugrave;ng sử dụng t&iacute;nh năng &quot;đặt hộ&quot; cho người th&acirc;n đ&atilde; tăng từ 15% đầu năm 2025 l&ecirc;n 40% v&agrave;o cuối năm 2025, giai đoạn nền tảng bắt đầu thử nghiệm v&agrave; triển khai t&iacute;nh năng beFamily.", "isoDate": "2026-03-24T02:08:00.000Z", "pubDate": "Tue, 24 Mar 26 09:08:00 +0700", "contentSnippet": "Theo dữ liệu từ Be Group công bố ngày 23.3, chỉ trong vòng một năm, tỷ lệ người dùng sử dụng tính năng \"đặt hộ\" cho người thân đã tăng từ 15% đầu năm 2025 lên 40% vào cuối năm 2025, giai đoạn nền tảng bắt đầu thử nghiệm và triển khai tính năng beFamily."}', '2026-04-05 15:13:21.983292+00', '2026-04-08 14:21:49.784874+00', '2026-04-06 15:25:44.335017+00', '2026-04-08 14:21:49.784874+00', 7, 'fdb6f7b1f83ea8694876551dbe2ef9ddb055f8d6ccd8dc9b7ba4f6948db6c62e', '2026-04-07 15:01:44.814448+00', 'ai-ner');
